public Program(){Boot("COMPILE");}
void Boot(string reason){_bootReason=reason;_bootTicks=BootDurationTicks;_scanTick=999;_screenTick=999;Runtime.UpdateFrequency=UpdateFrequency.Update10;LoadConfig();RefreshScreens();RefreshBlocks();}
public void Main(string argument,UpdateType updateSource){_tick++;if(Me.CustomData!=_lastCustomData){LoadConfig();RefreshScreens();RefreshBlocks();}bool refreshNow=argument.Equals("refresh",StringComparison.OrdinalIgnoreCase)||_bootTicks>0;if(++_screenTick>=30||refreshNow){RefreshScreens();_screenTick=0;}if(++_scanTick>=10||refreshNow){RefreshBlocks();_scanTick=0;}HandleCommand(argument);ScanMetrics();DrawAllScreens();if(_bootTicks>0)_bootTicks--;Echo(ScriptName+" v"+Version);Echo("Boot: "+_bootReason+(_bootTicks>0?" warming "+_bootTicks:" ready"));Echo("Screens: "+_screens.Count);if(_screens.Count>0)Echo("First LCD: "+_screens[0].Surface.SurfaceSize.X.ToString("0")+"x"+_screens[0].Surface.SurfaceSize.Y.ToString("0"));Echo("Mass: "+FormatKg(_m.TotalMassKg));Echo("State: "+_m.MasterState);}
void LoadConfig(){_lastCustomData=Me.CustomData;AutoReactorCharging=GetBool("Auto Reactor Charging",false);AutoHydrogenBalancing=GetBool("Auto Hydrogen Balancing",false);AutoAmmoBalancing=GetBool("Auto Ammo Balancing",false);GroupBatteries=GetString("Group Batteries",DefaultGroupBatteries);GroupReactors=GetString("Group Reactors",DefaultGroupReactors);GroupSolar=GetString("Group Solar Panels",DefaultGroupSolar);GroupHydrogenEngines=GetString("Group Hydrogen Engines",DefaultGroupHydrogenEngines);GroupHydrogen=GetString("Group Hydrogen Tanks",DefaultGroupHydrogen);GroupOxygen=GetString("Group Oxygen Tanks",DefaultGroupOxygen);GroupJump=GetString("Group Jump Drives",DefaultGroupJump);GroupTurrets=GetString("Group Turrets",DefaultGroupTurrets);GroupCargo=GetString("Group Cargo",DefaultGroupCargo);GroupVents=GetString("Group Air Vents",DefaultGroupVents);GroupThrusters=GetString("Group Thrusters",DefaultGroupThrusters);GroupLift=GetString("Group Lifting Thrusters",DefaultGroupLift);GroupCruise=GetString("Group Cruising Thrusters",DefaultGroupCruise);GroupBrake=GetString("Group Braking Thrusters",DefaultGroupBrake);GroupGyros=GetString("Group Gyros",DefaultGroupGyros);}
string GetString(string key,string fallback){string[]lines=Me.CustomData.Split('\n');for(int i=0;i<lines.Length;i++){string line=lines[i].Trim();int p=line.IndexOf('=');if(p<0)continue;string k=line.Substring(0,p).Trim();if(!k.Equals(key,StringComparison.OrdinalIgnoreCase))continue;string v=line.Substring(p+1).Trim();return v==""?fallback:v;}return fallback;}
bool GetBool(string key,bool fallback){string[]lines=Me.CustomData.Split('\n');for(int i=0;i<lines.Length;i++){string line=lines[i].Trim();int p=line.IndexOf('=');if(p<0)continue;string k=line.Substring(0,p).Trim();if(!k.Equals(key,StringComparison.OrdinalIgnoreCase))continue;string v=line.Substring(p+1).Trim();return v.Equals("true",StringComparison.OrdinalIgnoreCase)||v.Equals("yes",StringComparison.OrdinalIgnoreCase)||v.Equals("on",StringComparison.OrdinalIgnoreCase);}return fallback;}
void HandleCommand(string argument){if(string.IsNullOrWhiteSpace(argument))return;string a=argument.Trim().ToLower();if(a=="logo"||a=="splash")_page="splash";else if(a=="pilot"||a=="overview")_page="pilot";else if(a=="jump")_page="jump";else if(a=="cargo")_page="cargo";else if(a=="descent"||a=="takeoff")_page="descent";else if(a=="combat"||a=="turrets")_page="combat";else if(a=="damage")_page="damage";else if(a=="pressure")_page="pressure";else if(a=="thrusters")_page="thrusters";else if(a=="power"||a=="battery"||a=="batteries")_page="power";else if(a=="fuel"||a=="hydrogen"||a=="h2")_page="fuel";else if(a=="lifesupport"||a=="life"||a=="oxygen"||a=="o2")_page="lifesupport";else if(a=="ammo")_page="ammo";else if(a=="auto")_page="auto";else if(a=="predeparture"||a=="prejump"||a=="departure"||a=="checklist")_page="predeparture";else if(a=="abort")_m.FlightMode="MANUAL";}
void RefreshScreens(){_screens.Clear();IMyTextSurfaceProvider meProvider=Me as IMyTextSurfaceProvider;if(meProvider!=null&&meProvider.SurfaceCount>0)_screens.Add(new ScreenTarget("PB","splash",meProvider.GetSurface(0),true,"auto"));List<IMyTextSurfaceProvider>providers=new List<IMyTextSurfaceProvider>();GridTerminalSystem.GetBlocksOfType<IMyTextSurfaceProvider>(providers);for(int i=0;i<providers.Count;i++){IMyTerminalBlock block=providers[i]as IMyTerminalBlock;if(block==null||block.CubeGrid!=Me.CubeGrid)continue;if(!IsHorizonScreen(block))continue;ParseScreenBlock(block,providers[i]);}List<IMyTextPanel>panels=new List<IMyTextPanel>();GridTerminalSystem.GetBlocksOfType<IMyTextPanel>(panels,p=>p.CubeGrid==Me.CubeGrid);for(int i=0;i<panels.Count;i++){if(!IsHorizonScreen(panels[i]))continue;if(panels[i]is IMyTextSurfaceProvider)continue;ParseTextPanel(panels[i]);}}
bool IsHorizonScreen(IMyTerminalBlock block){return block.CustomName.Contains(LcdNameTag)||block.CustomName.Contains(CornerLcdNameTag);}
bool IsCornerScreen(IMyTerminalBlock block){return block.CustomName.Contains(CornerLcdNameTag);}
void ParseScreenBlock(IMyTerminalBlock block,IMyTextSurfaceProvider provider){string[]lines=block.CustomData.Split('\n');string page="";int surface=0;string layout="auto";bool hasPage=false;for(int i=0;i<lines.Length;i++){string line=lines[i].Trim();string foundPage=PageFromTag(line);if(foundPage!=""){if(hasPage)AddScreen(block,provider,page,surface,layout);page=foundPage;surface=0;layout="auto";hasPage=true;}else if(hasPage&&line.StartsWith("Surface=",StringComparison.OrdinalIgnoreCase)){int.TryParse(line.Substring(8).Trim(),out surface);}else if(hasPage&&line.StartsWith("Layout=",StringComparison.OrdinalIgnoreCase)){layout=CleanLayout(line.Substring(7).Trim());}}if(hasPage)AddScreen(block,provider,page,surface,layout);}
void ParseTextPanel(IMyTextPanel panel){string[]lines=panel.CustomData.Split('\n');string layout="auto";for(int i=0;i<lines.Length;i++){string line=lines[i].Trim();if(line.StartsWith("Layout=",StringComparison.OrdinalIgnoreCase)){layout=CleanLayout(line.Substring(7).Trim());continue;}string page=PageFromTag(line);if(page!=""){_screens.Add(new ScreenTarget(panel.CustomName,page,panel as IMyTextSurface,IsCornerScreen(panel),layout));return;}}}
string CleanLayout(string value){string v=value.ToLower();if(v=="bar"||v=="stack"||v=="full")return v;return"auto";}
string PageFromTag(string tag){string normalized=NormalizeTag(tag);if(normalized=="hssplash"||normalized=="hssplashscreen"||normalized=="hssplashdown")return"splash";if(normalized=="hspilot")return"pilot";if(normalized=="hsjump")return"jump";if(normalized=="hscargo")return"cargo";if(normalized=="hsdescent"||normalized=="hsinterplanetary"||normalized=="hsspace")return"descent";if(normalized=="hscombat")return"combat";if(normalized=="hsdamage")return"damage";if(normalized=="hspressure")return"pressure";if(normalized=="hsthrusters")return"thrusters";if(normalized=="hspower"||normalized=="hsbattery")return"power";if(normalized=="hsfuel"||normalized=="hshydrogen")return"fuel";if(normalized=="hslifesupport"||normalized=="hsoxygen")return"lifesupport";if(normalized=="hsammo")return"ammo";if(normalized=="hspredeparture"||normalized=="hsprejump"||normalized=="hsdeparture"||normalized=="hschecklist")return"predeparture";if(tag.Equals(TagSplash,StringComparison.OrdinalIgnoreCase))return"splash";if(tag.Equals(TagPilot,StringComparison.OrdinalIgnoreCase))return"pilot";if(tag.Equals(TagJump,StringComparison.OrdinalIgnoreCase))return"jump";if(tag.Equals(TagCargo,StringComparison.OrdinalIgnoreCase))return"cargo";if(tag.Equals(TagDescent,StringComparison.OrdinalIgnoreCase))return"descent";if(tag.Equals(TagCombat,StringComparison.OrdinalIgnoreCase))return"combat";if(tag.Equals(TagDamage,StringComparison.OrdinalIgnoreCase))return"damage";if(tag.Equals(TagPressure,StringComparison.OrdinalIgnoreCase))return"pressure";if(tag.Equals(TagThrusters,StringComparison.OrdinalIgnoreCase))return"thrusters";if(tag.Equals(TagPower,StringComparison.OrdinalIgnoreCase))return"power";if(tag.Equals(TagFuel,StringComparison.OrdinalIgnoreCase))return"fuel";if(tag.Equals(TagLifeSupport,StringComparison.OrdinalIgnoreCase))return"lifesupport";if(tag.Equals(TagBattery,StringComparison.OrdinalIgnoreCase))return"power";if(tag.Equals(TagHydrogen,StringComparison.OrdinalIgnoreCase))return"fuel";if(tag.Equals(TagOxygen,StringComparison.OrdinalIgnoreCase))return"lifesupport";if(tag.Equals(TagAmmo,StringComparison.OrdinalIgnoreCase))return"ammo";if(tag.Equals(TagPredeparture,StringComparison.OrdinalIgnoreCase))return"predeparture";return"";}
string NormalizeTag(string tag){string s=tag.Trim().ToLower();string result="";for(int i=0;i<s.Length;i++){char c=s[i];if((c>='a'&&c<='z')||(c>='0'&&c<='9'))result+=c;}return result;}
void AddScreen(IMyTerminalBlock block,IMyTextSurfaceProvider provider,string page,int index,string layout){if(provider.SurfaceCount==0)return;if(index<0||index>=provider.SurfaceCount)index=0;_screens.Add(new ScreenTarget(block.CustomName,page,provider.GetSurface(index),IsCornerScreen(block),layout));}
void RefreshBlocks(){_batteries.Clear();_reactors.Clear();_solar.Clear();_hydrogenEngines.Clear();_powerProducers.Clear();_gasGenerators.Clear();_hydrogenTanks.Clear();_oxygenTanks.Clear();_jumpDrives.Clear();_cargoBlocks.Clear();_turrets.Clear();_vents.Clear();_thrusters.Clear();_liftThrusters.Clear();_cruiseThrusters.Clear();_brakeThrusters.Clear();_gyros.Clear();_allBlocks.Clear();_tmpBlocks.Clear();GridTerminalSystem.GetBlocks(_tmpBlocks);for(int i=0;i<_tmpBlocks.Count;i++)if(_tmpBlocks[i].CubeGrid==Me.CubeGrid)_allBlocks.Add(_tmpBlocks[i]);GridTerminalSystem.GetBlocksOfType<IMyBatteryBlock>(_batteries,b=>b.CubeGrid==Me.CubeGrid);GridTerminalSystem.GetBlocksOfType<IMyJumpDrive>(_jumpDrives,b=>b.CubeGrid==Me.CubeGrid);GridTerminalSystem.GetBlocksOfType<IMyLargeTurretBase>(_turrets,b=>b.CubeGrid==Me.CubeGrid);GridTerminalSystem.GetBlocksOfType<IMyAirVent>(_vents,b=>b.CubeGrid==Me.CubeGrid);GridTerminalSystem.GetBlocksOfType<IMyThrust>(_thrusters,b=>b.CubeGrid==Me.CubeGrid);GridTerminalSystem.GetBlocksOfType<IMyGyro>(_gyros,b=>b.CubeGrid==Me.CubeGrid);GridTerminalSystem.GetBlocksOfType<IMyGasGenerator>(_gasGenerators,b=>b.CubeGrid==Me.CubeGrid);GridTerminalSystem.GetBlocksOfType<IMyPowerProducer>(_powerProducers,b=>b.CubeGrid==Me.CubeGrid);ClassifyPowerProducers();GetGroup(GroupBatteries,_batteries);GetGroup(GroupJump,_jumpDrives);GetGroup(GroupTurrets,_turrets);GetGroup(GroupVents,_vents);GetTagged(TagPressureVent,_vents);GetGroup(GroupThrusters,_thrusters);GetGroup(GroupLift,_liftThrusters);GetGroup(GroupCruise,_cruiseThrusters);GetGroup(GroupBrake,_brakeThrusters);GetGroup(GroupGyros,_gyros);GetPowerGroup(GroupReactors,_reactors);GetPowerGroup(GroupSolar,_solar);GetPowerGroup(GroupHydrogenEngines,_hydrogenEngines);_tmpTanks.Clear();GridTerminalSystem.GetBlocksOfType<IMyGasTank>(_tmpTanks,b=>b.CubeGrid==Me.CubeGrid);for(int i=0;i<_tmpTanks.Count;i++){IMyGasTank tank=_tmpTanks[i];if(tank==null)continue;string subtype=tank.BlockDefinition.SubtypeName.ToLower();string name=tank.CustomName.ToLower();if(subtype.Contains("hydrogen")||name.Contains("hydrogen")||name.Contains(" h2"))_hydrogenTanks.Add(tank);else if(subtype.Contains("oxygen")||name.Contains("oxygen")||name.Contains(" o2"))_oxygenTanks.Add(tank);}GetGroup(GroupHydrogen,_hydrogenTanks);GetGroup(GroupOxygen,_oxygenTanks);if(!GetTaggedCargoBlocks()){IMyBlockGroup cargoGroup=GridTerminalSystem.GetBlockGroupWithName(GroupCargo);if(cargoGroup!=null){_tmpBlocks.Clear();cargoGroup.GetBlocks(_tmpBlocks);for(int i=0;i<_tmpBlocks.Count;i++)if(_tmpBlocks[i].CubeGrid==Me.CubeGrid&&_tmpBlocks[i].InventoryCount>0)_cargoBlocks.Add(_tmpBlocks[i]);}else{_tmpBlocks.Clear();GridTerminalSystem.GetBlocks(_tmpBlocks);for(int i=0;i<_tmpBlocks.Count;i++)if(_tmpBlocks[i].CubeGrid==Me.CubeGrid&&_tmpBlocks[i].InventoryCount>0)_cargoBlocks.Add(_tmpBlocks[i]);}}}
bool GetTaggedCargoBlocks(){int count=0;for(int i=0;i<_allBlocks.Count;i++){if(_allBlocks[i].InventoryCount>0&&HasTag(_allBlocks[i],TagCargoBlock))count++;}if(count==0)return false;_cargoBlocks.Clear();for(int i=0;i<_allBlocks.Count;i++){if(_allBlocks[i].InventoryCount>0&&HasTag(_allBlocks[i],TagCargoBlock))_cargoBlocks.Add(_allBlocks[i]);}return true;}
void ClassifyPowerProducers(){for(int i=0;i<_powerProducers.Count;i++){IMyPowerProducer p=_powerProducers[i];string type=p.BlockDefinition.TypeIdString.ToLower();string subtype=p.BlockDefinition.SubtypeName.ToLower();string name=p.CustomName.ToLower();if(type.Contains("reactor")||subtype.Contains("reactor")||name.Contains("reactor"))_reactors.Add(p);else if(type.Contains("solarpanel")||subtype.Contains("solar")||name.Contains("solar"))_solar.Add(p);else if(type.Contains("hydrogenengine")||subtype.Contains("hydrogenengine")||name.Contains("hydrogen engine")||name.Contains("h2 engine"))_hydrogenEngines.Add(p);}}
bool GetTagged<T>(string tag,List<T>list)where T:class,IMyTerminalBlock{int count=0;for(int i=0;i<_allBlocks.Count;i++){if(_allBlocks[i]is T&&HasTag(_allBlocks[i],tag))count++;}if(count==0)return false;list.Clear();for(int i=0;i<_allBlocks.Count;i++){if(_allBlocks[i]is T&&HasTag(_allBlocks[i],tag))list.Add(_allBlocks[i]as T);}return true;}
bool HasTag(IMyTerminalBlock block,string tag){return block.CustomData.IndexOf(tag,StringComparison.OrdinalIgnoreCase)>=0;}
void GetGroup<T>(string name,List<T>list)where T:class,IMyTerminalBlock{IMyBlockGroup group=GridTerminalSystem.GetBlockGroupWithName(name);if(group==null)return;list.Clear();_tmpBlocks.Clear();group.GetBlocks(_tmpBlocks);for(int i=0;i<_tmpBlocks.Count;i++)if(_tmpBlocks[i].CubeGrid==Me.CubeGrid&&_tmpBlocks[i]is T)list.Add(_tmpBlocks[i]as T);}
void GetPowerGroup(string name,List<IMyPowerProducer>list){List<IMyPowerProducer>found=new List<IMyPowerProducer>();IMyBlockGroup group=GridTerminalSystem.GetBlockGroupWithName(name);if(group==null){_tmpBlocks.Clear();string key=name.Replace("HS ","");GridTerminalSystem.GetBlocks(_tmpBlocks);for(int i=0;i<_tmpBlocks.Count;i++)if(_tmpBlocks[i].CubeGrid==Me.CubeGrid&&_tmpBlocks[i].CustomName.Contains(key)&&_tmpBlocks[i]is IMyPowerProducer)found.Add(_tmpBlocks[i]as IMyPowerProducer);if(found.Count>0){list.Clear();for(int i=0;i<found.Count;i++)list.Add(found[i]);}return;}_tmpBlocks.Clear();group.GetBlocks(_tmpBlocks);for(int i=0;i<_tmpBlocks.Count;i++)if(_tmpBlocks[i].CubeGrid==Me.CubeGrid&&_tmpBlocks[i]is IMyPowerProducer)found.Add(_tmpBlocks[i]as IMyPowerProducer);if(found.Count>0){list.Clear();for(int i=0;i<found.Count;i++)list.Add(found[i]);}}
void ScanMetrics(){_m=new Metrics();_m.FlightMode="MANUAL";IMyShipController controller=FindController();if(controller!=null){MyShipMass mass=controller.CalculateShipMass();_m.BaseMassKg=mass.BaseMass;_m.TotalMassKg=mass.TotalMass;Vector3D gravity=controller.GetNaturalGravity();_m.NaturalGravity=(float)gravity.Length();_m.GravityPercent=_m.NaturalGravity/9.81f*100f;_m.VerticalSpeed=_m.NaturalGravity>0.01f?Vector3D.Dot(controller.GetShipVelocities().LinearVelocity,-Vector3D.Normalize(gravity)):0;}ScanPower();RunAutoReactorCharging();ScanTanks();ScanJump();ScanCargo();ScanTurrets();ScanPressure();ScanThrusters();ScanDamage();CalculateMasterState();ScanPredeparture();}
IMyShipController FindController(){List<IMyShipController>controllers=new List<IMyShipController>();GridTerminalSystem.GetBlocksOfType<IMyShipController>(controllers,c=>c.CubeGrid==Me.CubeGrid);for(int i=0;i<controllers.Count;i++)if(controllers[i].IsMainCockpit)return controllers[i];return controllers.Count>0?controllers[0]:null;}
void ScanPower(){double stored=0;double max=0;double input=0;double output=0;int online=0;for(int i=0;i<_batteries.Count;i++){IMyBatteryBlock b=_batteries[i];if(b.IsWorking)online++;stored+=b.CurrentStoredPower;max+=b.MaxStoredPower;input+=b.CurrentInput;output+=b.CurrentOutput;}_m.BatteryCount=_batteries.Count;_m.BatteryOnline=online;_m.BatteryPercent=Percent(stored,max);_m.BatteryStoredMWh=stored;_m.BatteryCapacityMWh=max;_m.PowerInputMw=input;_m.PowerOutputMw=output;_m.ReactorCount=_reactors.Count;_m.ReactorOnline=CountEnabledPower(_reactors);_m.ReactorUranium=ReactorUraniumSummary();SetReactorFuelLines();_m.SolarCount=_solar.Count;_m.HydrogenEngineCount=_hydrogenEngines.Count;_m.HydrogenEngineOnline=CountEnabledPower(_hydrogenEngines);}
void ScanTanks(){_m.FuelPercent=AverageTank(_hydrogenTanks,out _m.HydrogenOnline);_m.HydrogenCount=_hydrogenTanks.Count;_m.OxygenPercent=AverageTank(_oxygenTanks,out _m.OxygenOnline);_m.OxygenCount=_oxygenTanks.Count;_m.HydrogenImbalance=TankImbalance(_hydrogenTanks);SetTankLines();ScanGasGenerators();}
void SetTankLines(){_m.HydrogenTank1Name="H2 tank 1";_m.HydrogenTank1Value="-";_m.HydrogenTank1Percent=0;_m.HydrogenTank2Name="H2 tank 2";_m.HydrogenTank2Value="-";_m.HydrogenTank2Percent=0;if(_hydrogenTanks.Count>0){_m.HydrogenTank1Name=CleanBlockName(_hydrogenTanks[0].CustomName);_m.HydrogenTank1Percent=(float)(_hydrogenTanks[0].FilledRatio*100.0);_m.HydrogenTank1Value=FormatPct(_m.HydrogenTank1Percent);}if(_hydrogenTanks.Count>1){_m.HydrogenTank2Name=CleanBlockName(_hydrogenTanks[1].CustomName);_m.HydrogenTank2Percent=(float)(_hydrogenTanks[1].FilledRatio*100.0);_m.HydrogenTank2Value=FormatPct(_m.HydrogenTank2Percent);}}
int CountEnabledPower(List<IMyPowerProducer>blocks){int count=0;for(int i=0;i<blocks.Count;i++){IMyFunctionalBlock f=blocks[i]as IMyFunctionalBlock;if(f!=null&&f.Enabled&&f.IsFunctional)count++;}return count;}
void ScanGasGenerators(){MyItemType ice=MyItemType.MakeOre("Ice");double iceKg=0;int online=0;int working=0;for(int i=0;i<_gasGenerators.Count;i++){IMyGasGenerator g=_gasGenerators[i];if(g.Enabled)online++;if(g.IsWorking)working++;if(g.InventoryCount>0)iceKg+=(double)g.GetInventory(0).GetItemAmount(ice);}_m.GasGeneratorCount=_gasGenerators.Count;_m.GasGeneratorOnline=online;_m.GasGeneratorWorking=working;_m.GeneratorIceKg=iceKg;}
float AverageTank(List<IMyGasTank>tanks,out int online){online=0;double total=0;if(tanks.Count==0)return 0;for(int i=0;i<tanks.Count;i++){if(tanks[i].IsWorking)online++;total+=tanks[i].FilledRatio;}return(float)(total/tanks.Count*100.0);}
float TankImbalance(List<IMyGasTank>tanks){if(tanks.Count<2)return 0;double min=1;double max=0;for(int i=0;i<tanks.Count;i++){min=Math.Min(min,tanks[i].FilledRatio);max=Math.Max(max,tanks[i].FilledRatio);}return(float)((max-min)*100.0);}
void ScanJump(){double stored=0;double max=0;int online=0;int damaged=0;double rangeMeters=0;for(int i=0;i<_jumpDrives.Count;i++){IMyJumpDrive j=_jumpDrives[i];if(j.IsWorking)online++;if(!j.IsFunctional)damaged++;stored+=j.CurrentStoredPower;max+=j.MaxStoredPower;rangeMeters=Math.Max(rangeMeters,j.MaxJumpDistanceMeters);}double nowSec=DateTime.Now.TimeOfDay.TotalSeconds;double chargeRateMw=0;if(_lastJumpStoredMWh>=0&&_lastJumpSampleTime>=0){double dt=nowSec-_lastJumpSampleTime;if(dt>=0.5){double rawRate=(stored-_lastJumpStoredMWh)/dt*3600.0;if(rawRate>=0){_jumpRateSamples[_jumpRateSampleIdx%8]=rawRate;_jumpRateSampleIdx++;if(_jumpRateSampleCount<8)_jumpRateSampleCount++;}_lastJumpStoredMWh=stored;_lastJumpSampleTime=nowSec;double sum=0;for(int si=0;si<_jumpRateSampleCount;si++)sum+=_jumpRateSamples[si];double avg=_jumpRateSampleCount>0?sum/_jumpRateSampleCount:0;if(avg>0.001)_jumpRateSmoothed=avg;}}else{_lastJumpStoredMWh=stored;_lastJumpSampleTime=nowSec;}chargeRateMw=_jumpRateSmoothed;_m.JumpCount=_jumpDrives.Count;_m.JumpOnline=online;_m.JumpDamaged=damaged;_m.JumpPercent=Percent(stored,max);_m.JumpStoredMWh=stored;_m.JumpCapacityMWh=max;_m.JumpChargeRateMw=chargeRateMw;_m.JumpRangeKm=rangeMeters/1000.0;_m.JumpEta=JumpEtaText(max-stored,chargeRateMw);if(_m.JumpCount==0)_m.JumpState="NO DRIVES";else if(damaged>0)_m.JumpState="DAMAGED";else if(online<_m.JumpCount)_m.JumpState="OFFLINE";else if(_m.JumpPercent>=99.5f){_m.JumpState="READY";_jumpRateSmoothed=0;_jumpRateSampleCount=0;_jumpRateSampleIdx=0;}else _m.JumpState="CHARGING";}
void ScanCargo(){double used=0;double max=0;double mass=0;Dictionary<string,double>itemAmounts=new Dictionary<string,double>(StringComparer.OrdinalIgnoreCase);string c1="-";string c2="-";string c3="-";string c4="-";float c1p=0;float c2p=0;float c3p=0;float c4p=0;for(int b=0;b<_cargoBlocks.Count;b++){double blockUsed=0;double blockMax=0;for(int i=0;i<_cargoBlocks[b].InventoryCount;i++){IMyInventory inv=_cargoBlocks[b].GetInventory(i);used+=(double)inv.CurrentVolume;max+=(double)inv.MaxVolume;blockUsed+=(double)inv.CurrentVolume;blockMax+=(double)inv.MaxVolume;mass+=(double)inv.CurrentMass;_items.Clear();inv.GetItems(_items);for(int x=0;x<_items.Count;x++){string key=ShortItemName(_items[x].Type);double amount=(double)_items[x].Amount;if(itemAmounts.ContainsKey(key))itemAmounts[key]+=amount;else itemAmounts[key]=amount;}}float blockPercent=Percent(blockUsed,blockMax);string line=CleanBlockName(_cargoBlocks[b].CustomName)+"  "+FormatPct(blockPercent);if(b==0){c1=line;c1p=blockPercent;}else if(b==1){c2=line;c2p=blockPercent;}else if(b==2){c3=line;c3p=blockPercent;}else if(b==3){c4=line;c4p=blockPercent;}}_m.CargoBlocks=_cargoBlocks.Count;_m.CargoPercent=Percent(used,max);_m.CargoMassKg=mass;_m.CargoDensityKgPerL=used>0?(float)(mass/(used*1000.0)):0;_m.CargoBlock1=c1;_m.CargoBlock2=c2;_m.CargoBlock3=c3;_m.CargoBlock4=c4;_m.CargoBlock1Percent=c1p;_m.CargoBlock2Percent=c2p;_m.CargoBlock3Percent=c3p;_m.CargoBlock4Percent=c4p;SetTopCargoItems(itemAmounts);}
void ScanTurrets(){int online=0;int damaged=0;double ammoMass=0;int depleted=0;int ammoItems=0;string sample="";string t1="-";string t2="-";string t3="-";string t4="-";for(int i=0;i<_turrets.Count;i++){IMyLargeTurretBase t=_turrets[i];if(t.IsWorking)online++;if(!t.IsFunctional)damaged++;double turretAmmo=0;double turretAmmoAmount=0;for(int inv=0;inv<t.InventoryCount;inv++){IMyInventory inventory=t.GetInventory(inv);ammoMass+=(double)inventory.CurrentMass;turretAmmo+=(double)inventory.CurrentMass;_items.Clear();inventory.GetItems(_items);for(int x=0;x<_items.Count;x++){ammoItems++;turretAmmoAmount+=(double)_items[x].Amount;if(sample=="")sample=ShortItemName(_items[x].Type);}}if(t.IsFunctional&&turretAmmo<=0.001)depleted++;string state=!t.IsFunctional?"DAMAGED":(t.IsWorking?"ONLINE":"OFFLINE");string line=CleanBlockName(t.CustomName)+"  "+state+"  ammo "+turretAmmoAmount.ToString("0");if(i==0)t1=line;else if(i==1)t2=line;else if(i==2)t3=line;else if(i==3)t4=line;}_m.TurretCount=_turrets.Count;_m.TurretOnline=online;_m.TurretDamaged=damaged;_m.AmmoMassKg=ammoMass;_m.TurretDepleted=depleted;_m.AmmoItemStacks=ammoItems;_m.AmmoSample=sample==""?"none":sample;_m.TurretLine1=t1;_m.TurretLine2=t2;_m.TurretLine3=t3;_m.TurretLine4=t4;}
void ScanPressure(){int online=0;int pressurized=0;double pressure=0;int depressurize=0;string leak1="-";string leak2="-";string leak3="-";for(int i=0;i<_vents.Count;i++){IMyAirVent v=_vents[i];if(v.IsWorking)online++;if(v.Status==VentStatus.Pressurized)pressurized++;if(v.Depressurize)depressurize++;pressure+=v.GetOxygenLevel();bool leaking=!v.Depressurize&&v.Status==VentStatus.Depressurized;if(leaking){string line=CleanBlockName(v.CustomName)+"  "+v.Status.ToString();if(leak1=="-")leak1=line;else if(leak2=="-")leak2=line;else if(leak3=="-")leak3=line;}}_m.VentCount=_vents.Count;_m.VentOnline=online;_m.PressurizedVents=pressurized;_m.DepressurizeVents=depressurize;_m.PressurePercent=_vents.Count>0?(float)(pressure/_vents.Count*100.0):0;_m.LeakVent1=leak1;_m.LeakVent2=leak2;_m.LeakVent3=leak3;_m.LifeSupportReason=LifeSupportReason();}
void ScanThrusters(){_m.ThrusterCount=_thrusters.Count;_m.ThrusterOnline=CountWorking(_thrusters);_m.LiftCount=_liftThrusters.Count;_m.LiftOnline=CountWorking(_liftThrusters);_m.CruiseCount=_cruiseThrusters.Count;_m.CruiseOnline=CountWorking(_cruiseThrusters);_m.BrakeCount=_brakeThrusters.Count;_m.BrakeOnline=CountWorking(_brakeThrusters);_m.LiftLoadPercent=ThrustLoad(_liftThrusters);_m.LiftCapacityPercent=LiftCapacity(_liftThrusters);_m.CruiseLoadPercent=ThrustLoad(_cruiseThrusters);_m.BrakeLoadPercent=ThrustLoad(_brakeThrusters);ScanLiftThrusters();}
void ScanLiftThrusters(){_m.LiftHydroCount=0;_m.LiftIonCount=0;_m.LiftAtmoCount=0;_m.LiftHydroOnline=0;_m.LiftIonOnline=0;_m.LiftAtmoOnline=0;_m.LiftReliableN=0;_m.LiftAtmoMaxN=0;for(int i=0;i<_liftThrusters.Count;i++){IMyThrust t=_liftThrusters[i];string sub=t.BlockDefinition.SubtypeName.ToLower();bool working=t.IsWorking;bool isAtmo=sub.Contains("atmospheric")||sub.Contains("atmo");bool isHydro=!isAtmo&&(sub.Contains("hydrogen")||sub.Contains("hydro"));if(isAtmo){_m.LiftAtmoCount++;if(working)_m.LiftAtmoOnline++;if(working)_m.LiftAtmoMaxN+=t.MaxThrust;}else if(isHydro){_m.LiftHydroCount++;if(working)_m.LiftHydroOnline++;if(working)_m.LiftReliableN+=t.MaxEffectiveThrust;}else{_m.LiftIonCount++;if(working)_m.LiftIonOnline++;if(working)_m.LiftReliableN+=t.MaxEffectiveThrust;}}_m.WeightForceN=_m.TotalMassKg*_m.NaturalGravity;if(_m.NaturalGravity<=0.01f||_m.WeightForceN<=0){_m.LiftReliablePct=100f;_m.LiftWithAtmoPct=100f;}else{_m.LiftReliablePct=(float)(_m.LiftReliableN/_m.WeightForceN*100.0);_m.LiftWithAtmoPct=(float)((_m.LiftReliableN+_m.LiftAtmoMaxN)/_m.WeightForceN*100.0);}int h2Consumers=_m.LiftHydroCount+_m.HydrogenEngineCount;if(h2Consumers==0){_m.FuelRoundTripOk=true;_m.FuelRoundTripNote="no H2 thrusters";}else if(_m.FuelPercent>=40f){_m.FuelRoundTripOk=true;_m.FuelRoundTripNote="sufficient";}else if(_m.FuelPercent>=25f){_m.FuelRoundTripOk=false;_m.FuelRoundTripNote="marginal, one way only";}else if(_m.FuelPercent>=10f){_m.FuelRoundTripOk=false;_m.FuelRoundTripNote="low, abort risk";}else{_m.FuelRoundTripOk=false;_m.FuelRoundTripNote="critical";}_m.DescentState=ComputePlanetarySafetyState(true);_m.AscentState=ComputePlanetarySafetyState(false);}
string ComputePlanetarySafetyState(bool forDescent){if(_m.NaturalGravity<=0.01f)return"SPACE";if(_m.LiftCount==0)return"NO LIFT GROUP";if(_m.LiftOnline==0)return"LIFT OFFLINE";bool reliableHover=_m.LiftReliablePct>=100f;bool reliableMargin=_m.LiftReliablePct>=150f;bool atmoHover=_m.LiftWithAtmoPct>=100f;bool atmoMargin=_m.LiftWithAtmoPct>=150f;bool hasAtmo=_m.LiftAtmoCount>0;bool fuelOk=forDescent?_m.FuelRoundTripOk:(_m.FuelPercent>=25f||_m.LiftHydroCount==0);bool fuelLow=!fuelOk&&(_m.FuelPercent>=10f);if(_m.VerticalSpeed<-8.0&&!reliableHover&&!atmoHover)return"ABORT";if(!reliableHover&&!atmoHover)return"DO NOT ENTER";if(!reliableHover&&atmoHover){if(!fuelOk)return"FUEL CRITICAL";return"ATMO ASSIST ONLY";}if(reliableHover&&!reliableMargin){if(!fuelOk)return"FUEL CRITICAL";if(fuelLow)return"FUEL LOW";return"LOW MARGIN";}if(!fuelOk)return"FUEL CRITICAL";if(fuelLow)return"FUEL LOW";return"SAFE";}
int CountWorking<T>(List<T>blocks)where T:class,IMyFunctionalBlock{int count=0;for(int i=0;i<blocks.Count;i++)if(blocks[i].IsWorking)count++;return count;}
float ThrustLoad(List<IMyThrust>thrusters){double current=0;double max=0;for(int i=0;i<thrusters.Count;i++){current+=thrusters[i].CurrentThrust;max+=thrusters[i].MaxEffectiveThrust;}return Percent(current,max);}
float LiftCapacity(List<IMyThrust>thrusters){if(_m.TotalMassKg<=0||_m.NaturalGravity<=0.01f)return 100;double lift=0;for(int i=0;i<thrusters.Count;i++){if(!thrusters[i].IsWorking)continue;lift+=thrusters[i].MaxEffectiveThrust;}double weight=_m.TotalMassKg*_m.NaturalGravity;return Percent(lift,weight);}
void ScanDamage(){int nonfunctional=0;int damaged=0;string first="";string second="";string third="";for(int i=0;i<_allBlocks.Count;i++){IMyFunctionalBlock f=_allBlocks[i]as IMyFunctionalBlock;float integrity=BlockIntegrity(_allBlocks[i]);if(integrity<99.9f){damaged++;string line=CleanBlockName(_allBlocks[i].CustomName)+"  "+integrity.ToString("0.0")+"%";if(first=="")first=line;else if(second=="")second=line;else if(third=="")third=line;}if(f!=null&&!f.IsFunctional){nonfunctional++;}}_m.BlockCount=_allBlocks.Count;_m.DamagedCount=damaged;_m.NonFunctionalCount=nonfunctional;_m.DamageItem1=first==""?"none":first;_m.DamageItem2=second==""?"-":second;_m.DamageItem3=third==""?"-":third;}
void CalculateMasterState(){_m.MasterState="READY";_m.MasterColor=Safe;bool liftCritical=_m.NaturalGravity>0.01f&&(_m.LiftCount==0||_m.LiftOnline==0||_m.LiftReliablePct<100f&&_m.LiftWithAtmoPct<100f);if(_m.DamagedCount>0||_m.FuelPercent<10||_m.BatteryPercent<10||liftCritical){_m.MasterState="CRITICAL";_m.MasterColor=Critical;return;}bool descentCaution=_m.NaturalGravity>0.01f&&(_m.DescentState=="LOW MARGIN"||_m.DescentState=="ATMO ASSIST ONLY"||_m.DescentState=="FUEL LOW"||_m.AscentState=="FUEL LOW"||_m.AscentState=="LOW MARGIN");bool reactorDepleted=_m.ReactorDepleted>0;if(_m.FuelPercent<25||_m.BatteryPercent<25||_m.CargoPercent>85||_m.JumpState=="DAMAGED"||_m.PressurePercent<80||descentCaution||reactorDepleted){_m.MasterState="CAUTION";_m.MasterColor=Caution;}}
