void DrawPage(IMyTextSurface surface,string page,bool compact,string layout){Prepare(surface);if(_bootTicks>0){DrawBoot(surface);return;}if(page=="splash"){DrawSplash(surface);return;}View v=GetView(surface);bool autoCompact=!layout.Equals("full",StringComparison.OrdinalIgnoreCase)&&IsNarrowScreen(v);if(compact||IsCompactLayout(layout)||autoCompact||page=="ammo"||page=="pressure"){DrawCompactPage(surface,page,layout);return;}if(page=="pilot")DrawPilot(surface,compact);else if(page=="jump")DrawJump(surface);else if(page=="cargo")DrawCargo(surface);else if(page=="descent")DrawDescent(surface);else if(page=="combat")DrawCombat(surface,compact);else if(page=="damage")DrawDamage(surface);else if(page=="pressure")DrawPressure(surface);else if(page=="thrusters")DrawThrusters(surface);else if(page=="power")DrawPowerStatus(surface);else if(page=="fuel")DrawFuelStatus(surface);else if(page=="lifesupport")DrawLifeSupportStatus(surface);else if(page=="predeparture")DrawPredeparture(surface);else DrawPilot(surface,compact);}
