void DrawCompactPage(IMyTextSurface surface,string page,string layout){if(page=="splash"){DrawSplash(surface);return;}View v=GetView(surface);MySpriteDrawFrame frame=surface.DrawFrame();DrawBackground(frame,v);string title="STATUS";string label="SYS";string value="--";string footer="";float percent=0;Color color=Muted;if(page=="jump"){title="JUMP";label="JUMP";value=FormatPct(_m.JumpPercent);footer=_m.JumpState+"  ETA "+_m.JumpEta;percent=_m.JumpPercent;color=StateColor(_m.JumpState);}else if(page=="combat"||page=="ammo"){title="COMBAT";label="GUN";value=_m.TurretOnline+"/"+_m.TurretCount;footer="depleted "+_m.TurretDepleted+"  ammo stacks "+_m.AmmoItemStacks;percent=Percent(_m.TurretOnline,Math.Max(_m.TurretCount,1));color=_m.TurretDamaged>0||_m.TurretDepleted>0?Critical:Safe;}else if(page=="power"||page=="pilot"){title="POWER";label="PWR";value=FormatPct(_m.BatteryPercent);footer=_batteries.Count+" batteries";if(_m.ReactorCount+_m.SolarCount+_m.HydrogenEngineCount>0)footer="R "+_m.ReactorCount+"  S "+_m.SolarCount+"  H2E "+_m.HydrogenEngineCount;percent=_m.BatteryPercent;color=StatusColor(_m.BatteryPercent,false);}else if(page=="fuel"){title="FUEL";label="H2";value=FormatPct(_m.FuelPercent);footer=_hydrogenTanks.Count+" tanks  Imb "+_m.HydrogenImbalance.ToString("0")+"%";percent=_m.FuelPercent;color=StatusColor(_m.FuelPercent,false);}else if(page=="lifesupport"){title="LIFE SUPPORT";label="O2";value=FormatPct(_m.OxygenPercent);footer=_oxygenTanks.Count+" tanks";percent=_m.OxygenPercent;color=StatusColor(_m.OxygenPercent,false);}else if(page=="pressure"){title="PRESSURIZATION";label="AIR";value=FormatPct(_m.PressurePercent);footer=PressureState()+"  "+_m.PressurizedVents+"/"+_m.VentCount;percent=_m.PressurePercent;color=StatusColor(_m.PressurePercent,false);}else if(page=="cargo"){title="CARGO";label="LOAD";value=FormatPct(_m.CargoPercent);footer=FormatKg(_m.CargoMassKg);percent=_m.CargoPercent;color=StatusColor(100-_m.CargoPercent,false);}else if(page=="descent"){string _cDesc=_m.NaturalGravity<=0.01f?"SPACE":(_m.DescentState??"SCANNING");string _cGrav=_m.NaturalGravity<=0.01f?"space":(_m.NaturalGravity/9.81f).ToString("0.00")+"g";title="INTERPLANETARY";label="LAND";value=_cDesc;footer=_cGrav+"  asc: "+(_m.NaturalGravity<=0.01f?"SPACE":(_m.AscentState??"SCANNING"));percent=_cDesc=="SAFE"?100f:(_cDesc=="LOW MARGIN"||_cDesc=="ATMO ASSIST ONLY"?60f:10f);color=DescentStateColor(_cDesc);}else if(page=="thrusters"){title="THRUST";label="LIFT";value=_m.LiftOnline+"/"+_m.LiftCount;footer=_m.ThrusterOnline+"/"+_m.ThrusterCount+" all";percent=Percent(_m.LiftOnline,Math.Max(_m.LiftCount,1));color=_m.LiftCount==0?Warning:Safe;}else if(page=="damage"){title="DAMAGE";label="DMG";value=_m.DamagedCount.ToString();footer=_m.DamagedCount==0?"NO DAMAGE":"REPAIR";percent=_m.DamagedCount==0?100:10;color=_m.DamagedCount==0?Safe:Critical;}if(layout.Equals("stack",StringComparison.OrdinalIgnoreCase)||IsTallScreen(v))DrawCompactStack(frame,v,title,label,value,footer,percent,color);else DrawCompactStatusBar(frame,v,title,label,value,footer,percent,color);frame.Dispose();}
void ScanPredeparture(){int failed=0;int caution=0;if(_m.JumpCount==0){_m.JumpCheckResult="FAIL  no jump drives";failed++;}else if(_m.JumpDamaged>0){_m.JumpCheckResult="FAIL  "+_m.JumpDamaged+" drives damaged";failed++;}else if(_m.JumpOnline<_m.JumpCount){_m.JumpCheckResult="FAIL  "+(_m.JumpCount-_m.JumpOnline)+" drives offline";failed++;}else if(_m.JumpPercent<99.5f){_m.JumpCheckResult="CAUTION  charging "+FormatPct(_m.JumpPercent)+"  ETA "+_m.JumpEta;caution++;}else{_m.JumpCheckResult="OK  "+_m.JumpCount+" drives ready  "+_m.JumpRangeKm.ToString("0")+" km";}_m.DrainRateMw=_m.PowerOutputMw-_m.PowerInputMw;double jumpEtaSec=0;if(_m.JumpPercent<99.5f&&_m.JumpChargeRateMw>0.001){double remainMWh=_m.JumpCapacityMWh-_m.JumpStoredMWh;jumpEtaSec=remainMWh/_m.JumpChargeRateMw*3600.0;}_m.SecondsToJumpReady=jumpEtaSec;double transitSec=_m.JumpPercent>=99.5f?120.0:jumpEtaSec+60.0;double battCapMWh=_m.BatteryCapacityMWh>0?_m.BatteryCapacityMWh:1;double drainMWh=_m.DrainRateMw*(transitSec/3600.0);double battAfterMWh=_m.BatteryStoredMWh-drainMWh;_m.BatteryAfterJumpPct=(float)(battAfterMWh/battCapMWh*100.0);_m.BatteryAfterJumpPct=Math.Max(0,Math.Min(100,_m.BatteryAfterJumpPct));bool reactorsOnline=_m.ReactorOnline>0;bool solarOnline=_m.SolarCount>0;bool h2EnginesOnline=_m.HydrogenEngineOnline>0;bool anyBackupOnline=reactorsOnline||solarOnline||h2EnginesOnline;bool reactorsDepleted=_m.ReactorDepleted>0;System.Text.StringBuilder srcSb=new System.Text.StringBuilder();if(reactorsOnline)srcSb.Append("reactor ");if(solarOnline)srcSb.Append("solar ");if(h2EnginesOnline)srcSb.Append("H2eng ");srcSb.Append("battery");string powerSrc=srcSb.ToString().Trim();bool battOkNow=_m.BatteryPercent>=25f;bool battOkAfter=_m.BatteryAfterJumpPct>=25f;if(!battOkNow&&!anyBackupOnline){_m.PowerCheckResult="FAIL  battery "+FormatPct(_m.BatteryPercent)+"  no backup power";failed++;}else if(!battOkNow&&anyBackupOnline){_m.PowerCheckResult="CAUTION  battery "+FormatPct(_m.BatteryPercent)+"  charging via "+powerSrc;caution++;}else if(!battOkAfter&&_m.DrainRateMw>0.01){_m.PowerCheckResult="CAUTION  est. arrival "+FormatPct(_m.BatteryAfterJumpPct)+"  drain "+FormatMW(_m.DrainRateMw);caution++;}else if(_m.DrainRateMw>0.01&&!anyBackupOnline){_m.PowerCheckResult="CAUTION  draining "+FormatMW(_m.DrainRateMw)+"  est arrival "+FormatPct(_m.BatteryAfterJumpPct);caution++;}else if(reactorsDepleted){_m.PowerCheckResult="CAUTION  "+_m.ReactorDepleted+" reactor(s) empty  refuel before jump";caution++;}else{_m.PowerCheckResult="OK  "+FormatPct(_m.BatteryPercent)+"  est arrival "+FormatPct(_m.BatteryAfterJumpPct)+"  "+powerSrc;}if(_m.TurretCount==0){_m.TurretCheckResult="OK  no turrets installed";}else if(_m.TurretDamaged>0){_m.TurretCheckResult="FAIL  "+_m.TurretDamaged+" damaged";failed++;}else if(_m.TurretDepleted>0){_m.TurretCheckResult="CAUTION  "+_m.TurretDepleted+" depleted";caution++;}else if(_m.TurretOnline<_m.TurretCount){_m.TurretCheckResult="FAIL  "+(_m.TurretCount-_m.TurretOnline)+" offline";failed++;}else{_m.TurretCheckResult="OK  "+_m.TurretCount+" online  "+_m.AmmoItemStacks+" ammo stacks";}if(_m.DamagedCount==0){_m.DamageCheckResult="OK  "+_m.BlockCount+" blocks intact";}else if(_m.NonFunctionalCount>0){_m.DamageCheckResult="FAIL  "+_m.NonFunctionalCount+" non-functional  "+_m.DamagedCount+" damaged";failed++;}else{_m.DamageCheckResult="CAUTION  "+_m.DamagedCount+" blocks damaged";caution++;}if(_m.VentCount==0){_m.PressureCheckResult="OK  no vents monitored";}else if(_m.PressurePercent<80f){_m.PressureCheckResult="FAIL  "+FormatPct(_m.PressurePercent)+"  "+(_m.LeakVent1!="-"?_m.LeakVent1:"check vents");failed++;}else if(_m.PressurePercent<95f){_m.PressureCheckResult="CAUTION  "+FormatPct(_m.PressurePercent)+" partial";caution++;}else{_m.PressureCheckResult="OK  pressurized  O2 "+FormatPct(_m.OxygenPercent);}bool inGravity=_m.NaturalGravity>0.01f;if(!inGravity){_m.WeightCheckResult="OK  in space  "+FormatKg(_m.TotalMassKg);}else if(_m.LiftCount==0){_m.WeightCheckResult="FAIL  no lift thrusters configured";failed++;}else if(_m.LiftOnline==0){_m.WeightCheckResult="FAIL  lift thrusters offline";failed++;}else{string wState=_m.DescentState??"SCANNING";bool wOk=wState=="SAFE"||wState=="LOW MARGIN";if(!wOk){_m.WeightCheckResult="FAIL  "+wState+"  "+FormatKg(_m.TotalMassKg);failed++;}else if(wState=="LOW MARGIN"){_m.WeightCheckResult="CAUTION  low lift margin  "+FormatKg(_m.TotalMassKg);caution++;}else{_m.WeightCheckResult="OK  lift "+FormatPct(_m.LiftReliablePct)+"  "+FormatKg(_m.TotalMassKg);}}if(_m.HydrogenCount==0&&_m.LiftHydroCount==0){_m.FuelCheckResult="OK  no H2 systems";}else if(_m.FuelPercent<10f){_m.FuelCheckResult="FAIL  "+FormatPct(_m.FuelPercent)+" critical";failed++;}else if(_m.FuelPercent<25f){_m.FuelCheckResult="CAUTION  "+FormatPct(_m.FuelPercent)+" low";caution++;}else{_m.FuelCheckResult="OK  "+FormatPct(_m.FuelPercent)+"  "+_m.HydrogenCount+" tanks";}_m.DepartureChecksFailed=failed;_m.DepartureChecksCaution=caution;if(failed>0)_m.DepartureVerdict="NOT READY";else if(caution>0)_m.DepartureVerdict="CAUTION";else _m.DepartureVerdict="GO";}
void DrawPredeparture(IMyTextSurface surface){View v=GetView(surface);MySpriteDrawFrame frame=surface.DrawFrame();Color verdictColor=_m.DepartureVerdict=="GO"?Safe:_m.DepartureVerdict=="CAUTION"?Caution:Critical;DrawInfoBackground(frame,v);DrawInfoHeader(frame,v,"PRE-DEPARTURE",_m.DepartureVerdict??"SCANNING",verdictColor);float y=v.Top+v.Unit*0.20f;float availableH=v.Bottom-v.Unit*0.05f-(v.Top+v.Unit*0.20f)-v.Unit*0.10f;int totalRows=8;float rowStep=Math.Max(v.Unit*0.060f,availableH/totalRows);string summaryStr=_m.DepartureChecksFailed>0?_m.DepartureChecksFailed+" FAILED  "+_m.DepartureChecksCaution+" caution":_m.DepartureChecksCaution>0?_m.DepartureChecksCaution+" items need attention":"all systems nominal";float summaryPct=_m.DepartureVerdict=="GO"?100f:_m.DepartureVerdict=="CAUTION"?60f:15f;DrawInfoBarRow(frame,v,y,"STATUS",summaryStr,summaryPct,verdictColor);y+=v.Unit*0.10f;DrawCheckRow(frame,v,y,"Jump drives",_m.JumpCheckResult??"SCANNING");y+=rowStep;DrawCheckRow(frame,v,y,"Power",_m.PowerCheckResult??"SCANNING");y+=rowStep;DrawCheckRow(frame,v,y,"Turrets",_m.TurretCheckResult??"SCANNING");y+=rowStep;DrawCheckRow(frame,v,y,"Damage",_m.DamageCheckResult??"SCANNING");y+=rowStep;DrawCheckRow(frame,v,y,"Pressure",_m.PressureCheckResult??"SCANNING");y+=rowStep;DrawCheckRow(frame,v,y,"Weight/lift",_m.WeightCheckResult??"SCANNING");y+=rowStep;DrawCheckRow(frame,v,y,"Fuel H2",_m.FuelCheckResult??"SCANNING");y+=rowStep;if(_m.BatteryCapacityMWh>0&&y+rowStep<=v.Bottom-v.Unit*0.05f){string drainStr=_m.DrainRateMw>0.01?"drain "+FormatMW(_m.DrainRateMw)+"  arrival est. "+FormatPct(_m.BatteryAfterJumpPct):_m.DrainRateMw<-0.01?"charging "+FormatMW(-_m.DrainRateMw):"stable";Color drainCol=_m.BatteryAfterJumpPct>=50f?Safe:_m.BatteryAfterJumpPct>=25f?Caution:Critical;DrawInfoRow(frame,v,y,"Battery projection",drainStr,drainCol);}frame.Dispose();}
void DrawCheckRow(MySpriteDrawFrame frame,View v,float y,string label,string result){Color valueColor;string upper=result==null?"":result.ToUpper();if(upper.StartsWith("OK"))valueColor=Safe;else if(upper.StartsWith("CAUTION"))valueColor=Caution;else if(upper.StartsWith("FAIL"))valueColor=Critical;else valueColor=Muted;string display=result??"SCANNING";int sep=display.IndexOf("  ");if(sep>=0&&sep<10)display=display.Substring(sep+2).Trim();if(display.Length>32)display=display.Substring(0,32);DrawInfoRow(frame,v,y,label,display,valueColor);}
void DrawPilot(IMyTextSurface surface,bool compact){View v=GetView(surface);MySpriteDrawFrame frame=surface.DrawFrame();DrawInfoBackground(frame,v);DrawInfoHeader(frame,v,"PILOT STATUS",_m.MasterState,_m.MasterColor);float y=v.Top+v.Unit*0.20f;DrawInfoBarRow(frame,v,y,"Power",FormatPct(_m.BatteryPercent)+"  "+PowerStateText(),_m.BatteryPercent,BatteryColor(_m.BatteryPercent));y+=v.Unit*0.13f;DrawInfoBarRow(frame,v,y,"Fuel H2",FormatPct(_m.FuelPercent)+"  "+FuelStateText(),_m.FuelPercent,StatusColor(_m.FuelPercent,false));y+=v.Unit*0.13f;DrawInfoBarRow(frame,v,y,"Life support",PressureState()+"  "+FormatPct(_m.OxygenPercent),_m.OxygenPercent,StatusColor(_m.OxygenPercent,false));y+=v.Unit*0.12f;DrawInfoRow(frame,v,y,"Combat",TurretState()+"  ammo stacks "+_m.AmmoItemStacks,_m.TurretDamaged>0||_m.TurretDepleted>0?Caution:Safe);y+=v.Unit*0.075f;string _pilotGravStr=_m.NaturalGravity<=0.01f?"space":(_m.NaturalGravity/9.81f).ToString("0.00")+"g";string _pilotEntryState=PlanetEntryState();DrawInfoRow(frame,v,y,"Interplanetary",_pilotEntryState+"  "+_pilotGravStr,DescentStateColor(_pilotEntryState));y+=v.Unit*0.075f;DrawInfoRow(frame,v,y,"Jump",_m.JumpState+"  "+FormatPct(_m.JumpPercent)+"  ETA "+_m.JumpEta,StateColor(_m.JumpState));frame.Dispose();}
void DrawPowerStatus(IMyTextSurface surface){View v=GetView(surface);MySpriteDrawFrame frame=surface.DrawFrame();DrawInfoBackground(frame,v);DrawInfoHeader(frame,v,"POWER STATUS",PowerStateText(),PowerStateColor());float y=v.Top+v.Unit*0.22f;DrawInfoBarRow(frame,v,y,"Battery",FormatPct(_m.BatteryPercent),_m.BatteryPercent,BatteryColor(_m.BatteryPercent));y+=v.Unit*0.12f;DrawInfoRow(frame,v,y,"Stored",FormatMWh(_m.BatteryStoredMWh)+" / "+FormatMWh(_m.BatteryCapacityMWh),Accent);y+=v.Unit*0.075f;DrawInfoRow(frame,v,y,"Input",FormatMW(_m.PowerInputMw),Text);y+=v.Unit*0.075f;DrawInfoRow(frame,v,y,"Output",FormatMW(_m.PowerOutputMw),Text);y+=v.Unit*0.075f;DrawInfoRow(frame,v,y,"Batteries",_m.BatteryOnline+" online / "+_m.BatteryCount+" total",Text);y+=v.Unit*0.075f;DrawInfoRow(frame,v,y,"Reactors",_m.ReactorOnline+" online / "+_m.ReactorCount+" total",_m.ReactorCount>0?Text:Muted);y+=v.Unit*0.075f;Color uraniumColor=_m.ReactorDepleted>0?Critical:_m.ReactorCount>0?Accent:Muted;string uraniumStr=_m.ReactorDepleted>0?_m.ReactorUranium+"  "+_m.ReactorDepleted+" EMPTY":_m.ReactorUranium;DrawInfoRow(frame,v,y,"Uranium",uraniumStr,uraniumColor);y+=v.Unit*0.075f;string solarH2Str=_m.SolarCount+" solar";if(_m.HydrogenEngineCount>0)solarH2Str+="  "+_m.HydrogenEngineOnline+"/"+_m.HydrogenEngineCount+" H2eng";DrawInfoRow(frame,v,y,"Alt power",solarH2Str,(_m.SolarCount>0||_m.HydrogenEngineCount>0)?Text:Muted);y+=v.Unit*0.075f;string autoRcStr=!AutoReactorCharging?"disabled":_m.ReactorCount==0?"no reactors":_m.BatteryPercent>=99.5f?"reactors OFF - full":_m.BatteryPercent<25f?"reactors ON - charging":"reactors ON - hold";Color autoRcCol=!AutoReactorCharging?Muted:_m.BatteryPercent>=99.5f?Safe:_m.BatteryPercent<25f?Warning:Caution;DrawInfoRow(frame,v,y,"Auto reactor",autoRcStr,autoRcCol);frame.Dispose();}
void DrawFuelStatus(IMyTextSurface surface){View v=GetView(surface);MySpriteDrawFrame frame=surface.DrawFrame();DrawInfoBackground(frame,v);DrawInfoHeader(frame,v,"FUEL STATUS",FuelStateText(),StatusColor(_m.FuelPercent,false));float y=v.Top+v.Unit*0.20f;DrawInfoBarRow(frame,v,y,"Hydrogen tanks",FormatPct(_m.FuelPercent)+"  "+_m.HydrogenOnline+"/"+_m.HydrogenCount,_m.FuelPercent,StatusColor(_m.FuelPercent,false));y+=v.Unit*0.13f;int rows=Math.Min(4,Math.Max(1,_hydrogenTanks.Count));int start=ScrollStart(_hydrogenTanks.Count,rows);for(int r=0;r<rows;r++){if(_hydrogenTanks.Count==0)DrawInfoBarRow(frame,v,y,"H2 tank","-",0,Muted);else{IMyGasTank t=_hydrogenTanks[ScrollIndex(start,r,_hydrogenTanks.Count)];float pct=(float)(t.FilledRatio*100.0);DrawInfoBarRow(frame,v,y,CleanBlockName(t.CustomName),FormatPct(pct),pct,StatusColor(pct,false));}y+=v.Unit*0.105f;}DrawInfoRow(frame,v,y,"O2 / generators",FormatPct(_m.OxygenPercent)+" O2  "+_m.GasGeneratorWorking+"/"+_m.GasGeneratorCount+" gens",StatusColor(_m.OxygenPercent,false));y+=v.Unit*0.075f;DrawInfoRow(frame,v,y,"H2 engines",_m.HydrogenEngineCount>0?_m.HydrogenEngineOnline+" online / "+_m.HydrogenEngineCount:"none installed",_m.HydrogenEngineCount>0?Text:Muted);frame.Dispose();}
