void DrawJump(IMyTextSurface surface){View v=GetView(surface);MySpriteDrawFrame frame=surface.DrawFrame();DrawInfoBackground(frame,v);DrawInfoHeader(frame,v,"JUMP DRIVES",_m.JumpState,StateColor(_m.JumpState));float y=v.Top+v.Unit*0.22f;DrawInfoBarRow(frame,v,y,"Charge",FormatPct(_m.JumpPercent),_m.JumpPercent,StateColor(_m.JumpState));y+=v.Unit*0.13f;DrawInfoRow(frame,v,y,"Online",_m.JumpOnline+"/"+_m.JumpCount,_m.JumpOnline==_m.JumpCount?Safe:Caution);y+=v.Unit*0.075f;DrawInfoRow(frame,v,y,"ETA to full",_m.JumpEta,_m.JumpEta=="READY"?Safe:Caution);y+=v.Unit*0.075f;DrawInfoRow(frame,v,y,"Stored",FormatMWh(_m.JumpStoredMWh)+" / "+FormatMWh(_m.JumpCapacityMWh),Accent);y+=v.Unit*0.075f;DrawInfoRow(frame,v,y,"Charge rate",FormatMW(_m.JumpChargeRateMw),Text);y+=v.Unit*0.075f;DrawInfoRow(frame,v,y,"Range",_m.JumpRangeKm.ToString("0.0")+" km",Muted);frame.Dispose();}
void DrawCargo(IMyTextSurface surface){View v=GetView(surface);MySpriteDrawFrame frame=surface.DrawFrame();DrawInfoBackground(frame,v);DrawInfoHeader(frame,v,"CARGO STATUS",CargoState(),StatusColor(100-_m.CargoPercent,false));float y=v.Top+v.Unit*0.22f;DrawInfoBarRow(frame,v,y,"Fill",FormatPct(_m.CargoPercent),_m.CargoPercent,StatusColor(100-_m.CargoPercent,false));y+=v.Unit*0.13f;DrawInfoRow(frame,v,y,"Cargo mass",FormatKg(_m.CargoMassKg),Text);y+=v.Unit*0.075f;DrawInfoRow(frame,v,y,"Total mass",FormatKg(_m.TotalMassKg),Text);y+=v.Unit*0.075f;DrawInfoRow(frame,v,y,"Density",_m.CargoDensityKgPerL.ToString("0.00")+" kg/L",_m.CargoDensityKgPerL>10?Caution:Accent);y+=v.Unit*0.075f;DrawInfoRow(frame,v,y,"Inventory blocks",_m.CargoBlocks.ToString(),Muted);y+=v.Unit*0.075f;int rows=Math.Min(3,Math.Max(1,_cargoBlocks.Count));int start=ScrollStart(_cargoBlocks.Count,rows);for(int r=0;r<rows;r++){if(y+v.Unit*0.10f>v.Bottom-v.Unit*0.04f)break;if(_cargoBlocks.Count==0)DrawInfoBarRow(frame,v,y,"Container","-",0,Muted);else{IMyTerminalBlock b=_cargoBlocks[ScrollIndex(start,r,_cargoBlocks.Count)];double u=0,m=0;for(int i=0;i<b.InventoryCount;i++){IMyInventory inv=b.GetInventory(i);u+=(double)inv.CurrentVolume;m+=(double)inv.MaxVolume;}float pct=Percent(u,m);DrawInfoBarRow(frame,v,y,CleanBlockName(b.CustomName),FormatPct(pct),pct,StatusColor(100-pct,false));}y+=v.Unit*0.105f;}frame.Dispose();}
void DrawDescent(IMyTextSurface surface){View v=GetView(surface);MySpriteDrawFrame frame=surface.DrawFrame();string descentState=_m.NaturalGravity<=0.01f?"SPACE":(_m.DescentState??"SCANNING");Color headerColor=DescentStateColor(descentState);DrawInfoBackground(frame,v);DrawInfoHeader(frame,v,"INTERPLANETARY",descentState,headerColor);float y=v.Top+v.Unit*0.20f;string gravStr;if(_m.NaturalGravity<=0.01f)gravStr="none  (space)";else gravStr=(_m.NaturalGravity/9.81f).ToString("0.00")+" g  ("+_m.GravityPercent.ToString("0")+"%)";Color gravColor=_m.NaturalGravity<=0.01f?Muted:_m.NaturalGravity>11.0f?Critical:_m.NaturalGravity>9.0f?Warning:Caution;DrawInfoRow(frame,v,y,"Gravity",gravStr,gravColor);y+=v.Unit*0.075f;double shipMassKg=_m.TotalMassKg-_m.CargoMassKg;DrawInfoRow(frame,v,y,"Ship mass",FormatKg(shipMassKg),Text);y+=v.Unit*0.075f;DrawInfoRow(frame,v,y,"Cargo mass",FormatKg(_m.CargoMassKg)+"  ("+FormatPct(_m.CargoPercent)+")",StatusColor(100-_m.CargoPercent,false));y+=v.Unit*0.075f;DrawInfoRow(frame,v,y,"Total mass",FormatKg(_m.TotalMassKg),Text);y+=v.Unit*0.075f;string weightStr=_m.NaturalGravity<=0.01f?"n/a":FormatForceKN(_m.WeightForceN);DrawInfoRow(frame,v,y,"Weight force",weightStr,_m.NaturalGravity<=0.01f?Muted:Text);y+=v.Unit*0.075f;string reliableStr;Color reliableColor;if(_m.NaturalGravity<=0.01f){reliableStr=FormatForceKN(_m.LiftReliableN)+"  (space)";reliableColor=Safe;}else if(_m.WeightForceN<=0){reliableStr=FormatForceKN(_m.LiftReliableN);reliableColor=Safe;}else{reliableStr=FormatForceKN(_m.LiftReliableN)+"  "+FormatPct(_m.LiftReliablePct)+" of weight";reliableColor=_m.LiftReliablePct>=150f?Safe:_m.LiftReliablePct>=100f?Caution:Critical;}string reliableLabel="H2+Ion lift ("+_m.LiftHydroCount+"H2 "+_m.LiftIonCount+"Ion)";DrawInfoBarRow(frame,v,y,reliableLabel,reliableStr,Math.Min(_m.LiftReliablePct,150f)/150f*100f,reliableColor);y+=v.Unit*0.11f;if(_m.LiftAtmoCount>0){string atmoStr;Color atmoColor;if(_m.NaturalGravity<=0.01f){atmoStr=_m.LiftAtmoCount+" thrusters  (needs air)";atmoColor=Muted;}else{atmoStr=FormatForceKN(_m.LiftAtmoMaxN)+" max  "+FormatPct(_m.LiftWithAtmoPct)+" total";atmoColor=_m.LiftWithAtmoPct>=150f?Safe:_m.LiftWithAtmoPct>=100f?Caution:Critical;}DrawInfoBarRow(frame,v,y,"Atmo assist ("+_m.LiftAtmoCount+")",atmoStr,Math.Min(_m.LiftWithAtmoPct,150f)/150f*100f,atmoColor);y+=v.Unit*0.11f;}Color fuelColor=_m.FuelRoundTripOk?Safe:_m.FuelPercent>=25f?Caution:_m.FuelPercent>=10f?Warning:Critical;string fuelStr=FormatPct(_m.FuelPercent)+"  "+(_m.FuelRoundTripNote??"");DrawInfoBarRow(frame,v,y,"Fuel H2",fuelStr,_m.FuelPercent,fuelColor);y+=v.Unit*0.11f;float rowGuard=v.Bottom-v.Unit*0.06f;string ascentState=_m.NaturalGravity<=0.01f?"SPACE":(_m.AscentState??"SCANNING");if(y<=rowGuard){DrawInfoRow(frame,v,y,"Descent",descentState,headerColor);y+=v.Unit*0.070f;}if(y<=rowGuard){DrawInfoRow(frame,v,y,"Ascent",ascentState,DescentStateColor(ascentState));y+=v.Unit*0.070f;}if(y<=rowGuard){Color vsColor=_m.VerticalSpeed<-10.0?Critical:_m.VerticalSpeed<-3.0?Warning:Text;DrawInfoRow(frame,v,y,"Vertical speed",_m.VerticalSpeed.ToString("0.0")+" m/s",vsColor);}frame.Dispose();}
string FormatForceKN(double newtons){double kn=newtons/1000.0;if(kn>=1000.0)return(kn/1000.0).ToString("0.0")+" MN";return kn.ToString("0.0")+" kN";}
Color DescentStateColor(string state){if(state==null)return Muted;string s=state.ToUpper();if(s=="SAFE")return Safe;if(s=="SPACE")return Muted;if(s=="SCANNING")return Muted;if(s=="LOW MARGIN")return Caution;if(s=="ATMO ASSIST ONLY")return Caution;if(s=="FUEL LOW")return Warning;if(s=="ABORT")return Critical;if(s=="DO NOT ENTER")return Critical;if(s=="FUEL CRITICAL")return Critical;if(s=="LIFT OFFLINE")return Critical;if(s=="NO LIFT GROUP")return Critical;return Warning;}
void DrawCombat(IMyTextSurface surface,bool compact){View v=GetView(surface);MySpriteDrawFrame frame=surface.DrawFrame();DrawInfoBackground(frame,v);DrawInfoHeader(frame,v,"COMBAT",TurretState(),_m.TurretDamaged>0?Critical:Safe);float y=v.Top+v.Unit*0.22f;float turretPercent=Percent(_m.TurretOnline,Math.Max(_m.TurretCount,1));DrawInfoBarRow(frame,v,y,"Turrets",_m.TurretOnline+"/"+_m.TurretCount,turretPercent,_m.TurretDamaged>0?Critical:Safe);y+=v.Unit*0.13f;int rows=Math.Min(5,Math.Max(1,_turrets.Count));int start=ScrollStart(_turrets.Count,rows);for(int r=0;r<rows;r++){string line="-";if(_turrets.Count>0){IMyLargeTurretBase t=_turrets[ScrollIndex(start,r,_turrets.Count)];line=TurretStatusLine(t);}DrawInfoRow(frame,v,y,"Turret",line,TurretLineColor(line));y+=v.Unit*0.075f;}DrawInfoRow(frame,v,y,"Depleted / damaged",_m.TurretDepleted+" depleted  "+_m.TurretDamaged+" damaged",_m.TurretDepleted==0&&_m.TurretDamaged==0?Safe:Critical);frame.Dispose();}
void DrawDamage(IMyTextSurface surface){View v=GetView(surface);MySpriteDrawFrame frame=surface.DrawFrame();DrawInfoBackground(frame,v);DrawInfoHeader(frame,v,"DAMAGE",_m.DamagedCount==0?"NO DAMAGE":"REPAIR",_m.DamagedCount==0?Safe:Critical);float y=v.Top+v.Unit*0.22f;float integrity=100f-Percent(_m.DamagedCount,Math.Max(_m.BlockCount,1));DrawInfoBarRow(frame,v,y,"Integrity",FormatPct(integrity),integrity,_m.DamagedCount==0?Safe:Critical);y+=v.Unit*0.13f;DrawInfoRow(frame,v,y,"Damaged blocks",_m.DamagedCount+"/"+_m.BlockCount,_m.DamagedCount==0?Safe:Critical);y+=v.Unit*0.075f;DrawInfoRow(frame,v,y,"Non-functional",_m.NonFunctionalCount.ToString(),_m.NonFunctionalCount==0?Safe:Critical);y+=v.Unit*0.075f;if(_m.DamagedCount==0){DrawInfoRow(frame,v,y,"Damage","No damaged terminal blocks",Safe);}else{int rows=4;int drawn=0;for(int i=0;i<_allBlocks.Count&&drawn<rows;i++){float hp=BlockIntegrity(_allBlocks[i]);if(hp>=99.9f)continue;DrawInfoRow(frame,v,y,"Damage",CleanBlockName(_allBlocks[i].CustomName)+"  "+hp.ToString("0.0")+"%",Critical);y+=v.Unit*0.075f;drawn++;}}frame.Dispose();}
void DrawPressure(IMyTextSurface surface){View v=GetView(surface);MySpriteDrawFrame frame=surface.DrawFrame();DrawInfoBackground(frame,v);DrawInfoHeader(frame,v,"PRESSURE",PressureState(),StatusColor(_m.PressurePercent,false));float y=v.Top+v.Unit*0.22f;DrawInfoBarRow(frame,v,y,"Pressurization",FormatPct(_m.PressurePercent),_m.PressurePercent,StatusColor(_m.PressurePercent,false));y+=v.Unit*0.13f;DrawInfoRow(frame,v,y,"Vents OK",_m.PressurizedVents+"/"+_m.VentCount,_m.PressurePercent>=95?Safe:Caution);y+=v.Unit*0.075f;DrawInfoRow(frame,v,y,"Depressurize",_m.DepressurizeVents.ToString(),_m.DepressurizeVents==0?Text:Warning);y+=v.Unit*0.075f;DrawInfoRow(frame,v,y,"Oxygen",FormatPct(_m.OxygenPercent),StatusColor(_m.OxygenPercent,false));y+=v.Unit*0.075f;DrawInfoRow(frame,v,y,"State",PressureState(),StatusColor(_m.PressurePercent,false));frame.Dispose();}
void DrawThrusters(IMyTextSurface surface){View v=GetView(surface);MySpriteDrawFrame frame=surface.DrawFrame();DrawInfoBackground(frame,v);DrawInfoHeader(frame,v,"THRUSTERS",ThrusterState(),ThrusterStateColor());float y=v.Top+v.Unit*0.20f;float thrusterPercent=Percent(_m.ThrusterOnline,Math.Max(_m.ThrusterCount,1));DrawInfoBarRow(frame,v,y,"All thrusters",_m.ThrusterOnline+"/"+_m.ThrusterCount,thrusterPercent,ThrusterStateColor());y+=v.Unit*0.13f;DrawInfoBarRow(frame,v,y,"Lift load",FormatPct(_m.LiftLoadPercent),_m.LiftLoadPercent,LiftStatusColor());y+=v.Unit*0.13f;DrawInfoBarRow(frame,v,y,"Lift capacity",FormatPct(_m.LiftCapacityPercent),Math.Min(_m.LiftCapacityPercent,100),LiftStatusColor());y+=v.Unit*0.12f;DrawInfoRow(frame,v,y,"Lift group",_m.LiftOnline+"/"+_m.LiftCount,LiftStatusColor());y+=v.Unit*0.075f;DrawInfoRow(frame,v,y,"Cruise group",ThrusterGroupState(_m.CruiseOnline,_m.CruiseCount)+"  load "+FormatPct(_m.CruiseLoadPercent),_m.CruiseCount==0?Muted:Safe);y+=v.Unit*0.075f;DrawInfoRow(frame,v,y,"Brake group",ThrusterGroupState(_m.BrakeOnline,_m.BrakeCount)+"  load "+FormatPct(_m.BrakeLoadPercent),_m.BrakeCount==0?Muted:Safe);frame.Dispose();}
void DrawSplash(IMyTextSurface surface){View v=GetView(surface);float unit=v.Unit;float skyBottom=v.Top+v.H*0.38f;float dawnBottom=v.Top+v.H*0.50f;float oceanBottom=v.Top+v.H*0.74f;float horizonY=dawnBottom;float pulse=0.35f+0.65f*(float)((Math.Sin(_tick*0.22)+1.0)*0.5);Color red=new Color(255,36,28,(byte)(70+185*pulse));MySpriteDrawFrame frame=surface.DrawFrame();DrawBox(frame,v.Center,v.Size,new Color(3,13,31));DrawBox(frame,new Vector2(v.Center.X,v.Top+v.H*0.24f),new Vector2(v.W,v.H*0.34f),new Color(20,32,55));DrawBox(frame,new Vector2(v.Center.X,skyBottom-v.H*0.035f),new Vector2(v.W,v.H*0.17f),new Color(88,48,50));DrawBox(frame,new Vector2(v.Center.X,skyBottom+(dawnBottom-skyBottom)*0.5f),new Vector2(v.W,dawnBottom-skyBottom),new Color(224,98,37));DrawCircle(frame,new Vector2(v.Center.X,dawnBottom),unit*0.25f,new Color(255,177,48));DrawCircle(frame,new Vector2(v.Center.X,dawnBottom+unit*0.01f),unit*0.15f,new Color(255,226,125));DrawBox(frame,new Vector2(v.Center.X,dawnBottom+(oceanBottom-dawnBottom)*0.5f),new Vector2(v.W,oceanBottom-dawnBottom),new Color(9,32,60));DrawBox(frame,new Vector2(v.Center.X,oceanBottom+(v.Bottom-oceanBottom)*0.5f),new Vector2(v.W,v.Bottom-oceanBottom),new Color(3,17,36));DrawLine(frame,new Vector2(v.Left,horizonY),new Vector2(v.Right,horizonY),unit*0.007f,new Color(255,172,51));Vector2 logoCenter=new Vector2(v.Center.X,v.Top+v.H*0.42f);DrawShield(frame,logoCenter+new Vector2(0,unit*0.005f),unit*0.56f,unit*0.030f,new Color(48,83,96));DrawShield(frame,logoCenter,unit*0.56f,unit*0.020f,Text);DrawSplashCrosshair(frame,logoCenter+new Vector2(0,unit*0.005f),unit*0.20f,unit*0.012f,Text,red,pulse);float titleY=v.Bottom-v.H*0.20f;DrawText(frame,ScriptName,new Vector2(v.Center.X,titleY),unit*0.00215f,Text,TextAlignment.CENTER);DrawTitleOrnament(frame,v.Center.X,titleY+unit*0.070f,unit*0.72f,unit*0.010f,Orange);frame.Dispose();}
void DrawSplashCrosshair(MySpriteDrawFrame frame,Vector2 center,float size,float thickness,Color white,Color red,float pulse){float half=size*0.50f;float gap=size*0.23f;float ring=size*0.58f;float spike=size*0.18f;float arcThick=Math.Max(thickness,size*0.015f);int segs=24;for(int i=0;i<segs;i++){float a0=(float)(Math.PI*2.0*i/segs);float a1=(float)(Math.PI*2.0*(i+0.75)/segs);Vector2 p0=center+new Vector2((float)Math.Cos(a0),(float)Math.Sin(a0))*ring*0.5f;Vector2 p1=center+new Vector2((float)Math.Cos(a1),(float)Math.Sin(a1))*ring*0.5f;DrawLine(frame,p0,p1,arcThick,white);}DrawLine(frame,center+new Vector2(-half,0),center+new Vector2(-gap,0),thickness,white);DrawLine(frame,center+new Vector2(gap,0),center+new Vector2(half,0),thickness,white);DrawLine(frame,center+new Vector2(0,-half),center+new Vector2(0,-gap),thickness,white);DrawLine(frame,center+new Vector2(0,gap),center+new Vector2(0,half),thickness,white);DrawTriangle(frame,center+new Vector2(0,-ring*0.50f-spike*0.35f),new Vector2(spike,spike*1.8f),0f,white);DrawTriangle(frame,center+new Vector2(0,ring*0.50f+spike*0.35f),new Vector2(spike,spike*1.8f),(float)Math.PI,white);DrawCircle(frame,center,size*(0.16f+0.08f*pulse),red);}
void DrawBoot(IMyTextSurface surface){View v=GetView(surface);MySpriteDrawFrame frame=surface.DrawFrame();float progress=Clamp((float)(BootDurationTicks-_bootTicks+1)/BootDurationTicks*100f,0,100);DrawInfoBackground(frame,v);DrawText(frame,ScriptName.ToUpper(),new Vector2(v.Center.X,v.Top+v.H*0.30f),v.Unit*0.00145f,Accent,TextAlignment.CENTER);DrawText(frame,"BOOTING "+_bootReason,new Vector2(v.Center.X,v.Top+v.H*0.43f),v.Unit*0.0010f,Text,TextAlignment.CENTER);DrawInfoBarRow(frame,v,v.Top+v.H*0.58f,"Loading systems",((int)progress).ToString()+"%",progress,progress>=100?Safe:Caution);DrawText(frame,"Screens "+_screens.Count+"  Blocks "+_allBlocks.Count,new Vector2(v.Center.X,v.Bottom-v.H*0.12f),v.Unit*0.00085f,Muted,TextAlignment.CENTER);frame.Dispose();}
void DrawBackground(MySpriteDrawFrame frame,View v){DrawBox(frame,v.Center,v.Size,Bg);DrawBox(frame,v.Center+new Vector2(0,v.H*0.18f),new Vector2(v.W,v.H*0.64f),new Color(2,13,18));DrawBox(frame,v.Center+new Vector2(0,v.H*0.18f),new Vector2(v.W,v.H*0.16f),Panel2);DrawLine(frame,new Vector2(v.Left+v.Unit*0.08f,v.Top+v.Unit*0.13f),new Vector2(v.Right-v.Unit*0.08f,v.Top+v.Unit*0.13f),v.Unit*0.006f,Orange);DrawRectOutline(frame,v.Center,v.Size-new Vector2(v.Unit*0.03f,v.Unit*0.03f),v.Unit*0.004f,new Color(0,95,105));}
void DrawHeader(MySpriteDrawFrame frame,View v,string title,string state,Color stateColor){DrawText(frame,title,new Vector2(v.Left+v.Unit*0.08f,v.Top+v.Unit*0.078f),v.Unit*0.00110f,Text,TextAlignment.LEFT);DrawText(frame,state,new Vector2(v.Right-v.Unit*0.08f,v.Top+v.Unit*0.078f),v.Unit*0.00110f,stateColor,TextAlignment.RIGHT);}
void DrawTile(MySpriteDrawFrame frame,View v,int col,int row,int cols,int rows,string label,string value,float percent,Color color,string icon){float margin=v.Unit*0.075f;float gap=v.Unit*0.035f;float areaTop=v.Top+v.H*0.205f;float areaH=v.H*0.62f;float cellW=(v.W-margin*2f-gap*(cols-1))/cols;float cellH=(areaH-gap*(rows-1))/rows;float maxH=rows==1?v.Unit*0.34f:v.Unit*0.30f;cellH=Math.Min(cellH,maxH);Vector2 size=new Vector2(cellW,cellH);Vector2 center=new Vector2(v.Left+margin+col*(cellW+gap)+cellW*0.5f,areaTop+row*(cellH+gap)+cellH*0.5f);percent=Clamp(percent,0,100);DrawBox(frame,center,size,new Color(0,6,8));DrawRectOutline(frame,center,size,v.Unit*0.009f,Accent);DrawCornerTicks(frame,center,size,v.Unit*0.020f,v.Unit*0.006f,Text);float iconSize=Math.Min(size.X,size.Y)*0.38f;DrawFsdIcon(frame,center+new Vector2(0,-size.Y*0.18f),iconSize,label,icon,color);DrawText(frame,value,center+new Vector2(0,size.Y*0.10f),v.Unit*0.00135f,color,TextAlignment.CENTER);DrawText(frame,label,center+new Vector2(0,size.Y*0.31f),v.Unit*0.00082f,Text,TextAlignment.CENTER);DrawSegmentBar(frame,center+new Vector2(0,size.Y*0.43f),size.X*0.72f,size.Y*0.060f,percent,color,8);}
void DrawCompactStatusBar(MySpriteDrawFrame frame,View v,string title,string label,string value,string footer,float percent,Color color){percent=Clamp(percent,0,100);float pad=v.H*0.14f;float titleScale=Math.Max(0.55f,Math.Min(v.H*0.00062f,v.W*0.00024f));float valueScale=Math.Max(0.48f,Math.Min(v.H*0.00060f,v.W*0.00023f));float rowScale=Math.Max(0.38f,Math.Min(v.H*0.00042f,v.W*0.00017f));float footerScale=Math.Max(0.34f,Math.Min(v.H*0.00038f,v.W*0.00015f));DrawBox(frame,v.Center,v.Size,Bg);DrawBox(frame,v.Center,new Vector2(v.W-pad*0.75f,v.H-pad*0.75f),new Color(0,8,11));DrawRectOutline(frame,v.Center,new Vector2(v.W-pad*0.65f,v.H-pad*0.65f),Math.Max(2f,v.H*0.025f),Accent);float left=v.Left+pad;float right=v.Right-pad;float topY=v.Top+v.H*0.15f;DrawText(frame,title,new Vector2(left,topY),titleScale,Text,TextAlignment.LEFT);DrawText(frame,value,new Vector2(right,topY),valueScale,color,TextAlignment.RIGHT);DrawLine(frame,new Vector2(left,v.Top+v.H*0.29f),new Vector2(right,v.Top+v.H*0.29f),Math.Max(2f,v.H*0.018f),Orange);DrawText(frame,label,new Vector2(left,v.Top+v.H*0.40f),rowScale,Muted,TextAlignment.LEFT);DrawText(frame,footer,new Vector2(right,v.Top+v.H*0.40f),rowScale,Muted,TextAlignment.RIGHT);float barY=v.Top+v.H*0.64f;float barW=v.W-pad*2f;float barH=Math.Max(5f,v.H*0.16f);DrawBox(frame,new Vector2(v.Center.X,barY),new Vector2(barW,barH),new Color(14,43,49));DrawBox(frame,new Vector2(left+barW*percent/100f*0.5f,barY),new Vector2(barW*percent/100f,barH),color);DrawRectOutline(frame,new Vector2(v.Center.X,barY),new Vector2(barW,barH),Math.Max(1.5f,v.H*0.010f),Muted);DrawSegmentTicks(frame,new Vector2(v.Center.X,barY),barW,barH,12,new Color(0,175,190));DrawText(frame,title+" STATUS",new Vector2(left,v.Bottom-v.H*0.10f),footerScale,Muted,TextAlignment.LEFT);DrawText(frame,value,new Vector2(right,v.Bottom-v.H*0.10f),footerScale,color,TextAlignment.RIGHT);}
void DrawCompactStack(MySpriteDrawFrame frame,View v,string title,string label,string value,string footer,float percent,Color color){percent=Clamp(percent,0,100);float pad=v.W*0.13f;float titleScale=Math.Max(0.45f,Math.Min(v.W*0.00070f,v.H*0.00023f));float valueScale=Math.Max(0.45f,Math.Min(v.W*0.00090f,v.H*0.00028f));float footerScale=Math.Max(0.32f,Math.Min(v.W*0.00048f,v.H*0.00018f));DrawBox(frame,v.Center,v.Size,Bg);DrawBox(frame,v.Center,new Vector2(v.W-pad*0.7f,v.H-pad*0.7f),new Color(0,8,11));DrawRectOutline(frame,v.Center,new Vector2(v.W-pad*0.6f,v.H-pad*0.6f),Math.Max(2f,v.W*0.020f),Accent);DrawText(frame,title,new Vector2(v.Center.X,v.Top+v.H*0.13f),titleScale,Text,TextAlignment.CENTER);DrawLine(frame,new Vector2(v.Left+pad,v.Top+v.H*0.21f),new Vector2(v.Right-pad,v.Top+v.H*0.21f),Math.Max(2f,v.W*0.016f),Orange);DrawText(frame,footer,new Vector2(v.Center.X,v.Top+v.H*0.27f),footerScale,Muted,TextAlignment.CENTER);Vector2 tileCenter=new Vector2(v.Center.X,v.Top+v.H*0.40f);Vector2 tileSize=new Vector2(v.W*0.52f,v.W*0.52f);DrawBox(frame,tileCenter,tileSize,new Color(0,6,8));DrawRectOutline(frame,tileCenter,tileSize,Math.Max(2f,v.W*0.018f),color);DrawText(frame,label.Length>3?label.Substring(0,3):label,tileCenter+new Vector2(0,-tileSize.Y*0.09f),valueScale*0.72f,color,TextAlignment.CENTER);DrawText(frame,value,new Vector2(v.Center.X,v.Top+v.H*0.62f),valueScale,color,TextAlignment.CENTER);DrawVerticalBar(frame,new Vector2(v.Center.X,v.Top+v.H*0.77f),v.W*0.16f,v.H*0.23f,percent,color,10);DrawText(frame,title+" "+value,new Vector2(v.Center.X,v.Bottom-v.H*0.08f),footerScale,color,TextAlignment.CENTER);}
void DrawVerticalBar(MySpriteDrawFrame frame,Vector2 center,float width,float height,float percent,Color color,int segments){percent=Clamp(percent,0,100);DrawBox(frame,center,new Vector2(width,height),new Color(14,43,49));float fillH=height*percent/100f;DrawBox(frame,new Vector2(center.X,center.Y+height*0.5f-fillH*0.5f),new Vector2(width,fillH),color);DrawRectOutline(frame,center,new Vector2(width,height),Math.Max(1.5f,width*0.08f),Muted);float top=center.Y-height*0.5f;for(int i=1;i<segments;i++){float y=top+height*i/segments;DrawLine(frame,new Vector2(center.X-width*0.48f,y),new Vector2(center.X+width*0.48f,y),Math.Max(1f,width*0.04f),new Color(0,175,190));}}
void DrawSegmentTicks(MySpriteDrawFrame frame,Vector2 center,float width,float height,int segments,Color color){float left=center.X-width*0.5f;for(int i=1;i<segments;i++){float x=left+width*i/segments;DrawLine(frame,new Vector2(x,center.Y-height*0.48f),new Vector2(x,center.Y+height*0.48f),Math.Max(1f,height*0.06f),color);}}
void DrawSegmentBar(MySpriteDrawFrame frame,Vector2 center,float width,float height,float percent,Color color,int segments){percent=Clamp(percent,0,100);float gap=Math.Max(1f,height*0.28f);float segW=(width-gap*(segments-1))/segments;float left=center.X-width*0.5f;int lit=(int)Math.Ceiling(percent/100f*segments);for(int i=0;i<segments;i++){Color c=i<lit?color:new Color(18,48,54);DrawBox(frame,new Vector2(left+i*(segW+gap)+segW*0.5f,center.Y),new Vector2(segW,height),c);}}
void DrawFsdIcon(MySpriteDrawFrame frame,Vector2 center,float size,string label,string icon,Color color){float t=size*0.075f;DrawRectOutline(frame,center,new Vector2(size,size),t,color);string l=label.ToUpper();if(l=="PWR"){DrawLine(frame,center+new Vector2(size*0.08f,-size*0.34f),center+new Vector2(-size*0.12f,-size*0.02f),t*1.4f,color);DrawLine(frame,center+new Vector2(-size*0.12f,-size*0.02f),center+new Vector2(size*0.12f,-size*0.02f),t*1.4f,color);DrawLine(frame,center+new Vector2(size*0.12f,-size*0.02f),center+new Vector2(-size*0.06f,size*0.34f),t*1.4f,color);}else if(l=="GRAV"||l=="TURRET"){DrawCircleOutline(frame,center,size*0.52f,t,color);DrawLine(frame,center+new Vector2(-size*0.32f,0),center+new Vector2(size*0.32f,0),t,color);DrawLine(frame,center+new Vector2(0,-size*0.32f),center+new Vector2(0,size*0.32f),t,color);}else if(l=="LOAD"||l=="FILL"||l=="MASS"){DrawBox(frame,center+new Vector2(0,size*0.10f),new Vector2(size*0.44f,size*0.36f),color);DrawBox(frame,center+new Vector2(0,size*-0.18f),new Vector2(size*0.30f,size*0.09f),color);}else if(l=="LIFT"||l=="AMMO"){DrawTriangle(frame,center,new Vector2(size*0.48f,size*0.55f),0f,color);}else if(l=="CRUISE"||l=="JUMP"){DrawLine(frame,center+new Vector2(-size*0.30f,0),center+new Vector2(size*0.25f,0),t*1.5f,color);DrawTriangle(frame,center+new Vector2(size*0.23f,0),new Vector2(size*0.24f,size*0.24f),(float)Math.PI*0.5f,color);}else if(l=="BRAKE"){DrawLine(frame,center+new Vector2(-size*0.25f,-size*0.25f),center+new Vector2(size*0.25f,size*0.25f),t*1.4f,color);DrawLine(frame,center+new Vector2(size*0.25f,-size*0.25f),center+new Vector2(-size*0.25f,size*0.25f),t*1.4f,color);}else{DrawText(frame,l.Length>2?l.Substring(0,2):l,center+new Vector2(0,-size*0.11f),size*0.0040f,color,TextAlignment.CENTER);}}
void DrawBar(MySpriteDrawFrame frame,View v,string label,float percent,string value,float y,Color color){float x=v.Center.X;float w=v.W*0.78f;float h=v.Unit*0.050f;percent=Clamp(percent,0,100);DrawText(frame,label,new Vector2(x-w*0.5f,y-h*1.35f),v.Unit*0.00105f,Text,TextAlignment.LEFT);DrawText(frame,value,new Vector2(x+w*0.5f,y-h*1.35f),v.Unit*0.00105f,Text,TextAlignment.RIGHT);DrawBox(frame,new Vector2(x,y),new Vector2(w,h),new Color(22,42,54));DrawBox(frame,new Vector2(x-w*0.5f+w*percent/100f*0.5f,y),new Vector2(w*percent/100f,h),color);DrawLine(frame,new Vector2(x-w*0.5f,y-h*0.52f),new Vector2(x+w*0.5f,y-h*0.52f),v.Unit*0.003f,Muted);DrawLine(frame,new Vector2(x-w*0.5f,y+h*0.52f),new Vector2(x+w*0.5f,y+h*0.52f),v.Unit*0.003f,Muted);}
void DrawGauge(MySpriteDrawFrame frame,Vector2 center,float size,float percent,Color color){percent=Clamp(percent,0,100);DrawCircle(frame,center,size,new Color(18,35,49));DrawCircleOutline(frame,center,size,size*0.055f,Muted);float angle=(float)(-Math.PI*0.75+Math.PI*1.5*percent/100f);Vector2 end=center+new Vector2((float)Math.Cos(angle),(float)Math.Sin(angle))*size*0.38f;DrawLine(frame,center,end,size*0.035f,color);DrawCircle(frame,center,size*0.11f,color);}
void DrawHalfGauge(MySpriteDrawFrame frame,Vector2 center,float size,float percent,Color color){percent=Clamp(percent,0,100);int segments=28;float radius=size*0.43f;float thickness=size*0.045f;Color empty=new Color(92,130,143);for(int i=0;i<segments;i++){float t0=(float)i/segments;float t1=(float)(i+1)/segments;float angle0=(float)Math.PI*(1f+t0);float angle1=(float)Math.PI*(1f+t1);Vector2 a=center+new Vector2((float)Math.Cos(angle0),(float)Math.Sin(angle0))*radius;Vector2 b=center+new Vector2((float)Math.Cos(angle1),(float)Math.Sin(angle1))*radius;DrawLine(frame,a,b,thickness,t1*100f<=percent?color:empty);}float needleAngle=(float)Math.PI*(1f+percent/100f);Vector2 end=center+new Vector2((float)Math.Cos(needleAngle),(float)Math.Sin(needleAngle))*radius*0.82f;DrawLine(frame,center,end,thickness*0.65f,color);DrawCircle(frame,center,size*0.075f,color);}
void DrawStatusLine(MySpriteDrawFrame frame,View v,string label,string value,float y,Color color){Vector2 center=new Vector2(v.Center.X,y);Vector2 size=new Vector2(v.W*0.76f,v.Unit*0.065f);DrawBox(frame,center,size,new Color(0,6,8));DrawRectOutline(frame,center,size,v.Unit*0.004f,Accent);DrawText(frame,label,new Vector2(center.X-size.X*0.44f,y-v.Unit*0.010f),v.Unit*0.00098f,Text,TextAlignment.LEFT);DrawText(frame,value,new Vector2(center.X+size.X*0.44f,y-v.Unit*0.010f),v.Unit*0.00098f,color,TextAlignment.RIGHT);}
void DrawInfoBackground(MySpriteDrawFrame frame,View v){DrawBox(frame,v.Center,v.Size,Bg);DrawBox(frame,v.Center,v.Size-new Vector2(v.Unit*0.04f,v.Unit*0.04f),Panel);DrawRectOutline(frame,v.Center,v.Size-new Vector2(v.Unit*0.04f,v.Unit*0.04f),v.Unit*0.006f,Accent);}
void DrawInfoHeader(MySpriteDrawFrame frame,View v,string title,string state,Color stateColor){DrawText(frame,title,new Vector2(v.Left+v.Unit*0.07f,v.Top+v.Unit*0.085f),v.Unit*0.00155f,Accent,TextAlignment.LEFT);DrawText(frame,state,new Vector2(v.Right-v.Unit*0.07f,v.Top+v.Unit*0.090f),v.Unit*0.00125f,stateColor,TextAlignment.RIGHT);DrawLine(frame,new Vector2(v.Left+v.Unit*0.07f,v.Top+v.Unit*0.135f),new Vector2(v.Right-v.Unit*0.07f,v.Top+v.Unit*0.135f),v.Unit*0.006f,Orange);}
void DrawInfoRow(MySpriteDrawFrame frame,View v,float y,string label,string value,Color valueColor){Vector2 center=new Vector2(v.Center.X,y);Vector2 size=new Vector2(v.W*0.84f,v.Unit*0.055f);DrawBox(frame,center,size,Panel2);DrawRectOutline(frame,center,size,v.Unit*0.0025f,Muted);DrawText(frame,label,new Vector2(center.X-size.X*0.46f,y-v.Unit*0.014f),v.Unit*0.00105f,Text,TextAlignment.LEFT);DrawText(frame,value,new Vector2(center.X+size.X*0.46f,y-v.Unit*0.014f),v.Unit*0.00110f,valueColor,TextAlignment.RIGHT);}
void DrawInfoBarRow(MySpriteDrawFrame frame,View v,float y,string label,string value,float percent,Color color){Vector2 center=new Vector2(v.Center.X,y);Vector2 size=new Vector2(v.W*0.84f,v.Unit*0.095f);DrawBox(frame,center,size,Panel2);DrawRectOutline(frame,center,size,v.Unit*0.003f,Muted);DrawText(frame,label,new Vector2(center.X-size.X*0.46f,y-size.Y*0.34f),v.Unit*0.00105f,Text,TextAlignment.LEFT);DrawText(frame,value,new Vector2(center.X+size.X*0.46f,y-size.Y*0.34f),v.Unit*0.00110f,color,TextAlignment.RIGHT);float barW=size.X*0.92f;float barH=size.Y*0.16f;Vector2 barCenter=new Vector2(center.X,y+size.Y*0.26f);DrawBox(frame,barCenter,new Vector2(barW,barH),new Color(18,48,32));DrawBox(frame,new Vector2(barCenter.X-barW*0.5f+barW*Clamp(percent,0,100)/100f*0.5f,barCenter.Y),new Vector2(barW*Clamp(percent,0,100)/100f,barH),color);DrawRectOutline(frame,barCenter,new Vector2(barW,barH),v.Unit*0.002f,Muted);}
int ScrollStart(int count,int rows){if(count<=rows||rows<=0)return 0;return(int)((_tick/18)%count);}
int ScrollIndex(int start,int row,int count){if(count<=0)return 0;return(start+row)%count;}
View GetView(IMyTextSurface surface){Vector2 size=surface.SurfaceSize;Vector2 offset=(surface.TextureSize-size)*0.5f;return new View(offset,size);}
bool IsNarrowScreen(View v){float ratio=v.W/Math.Max(v.H,1f);return ratio>2.35f||ratio<0.68f;}
bool IsCompactLayout(string layout){return layout.Equals("bar",StringComparison.OrdinalIgnoreCase)||layout.Equals("stack",StringComparison.OrdinalIgnoreCase);}
bool IsTallScreen(View v){return v.H>v.W*1.45f;}
float Percent(double value,double max){return max<=0?0:(float)(value/max*100.0);}
float Clamp(float v,float min,float max){return Math.Max(min,Math.Min(max,v));}
Color StatusColor(float percent,bool inverse){float p=inverse?100-percent:percent;if(p>=50)return Safe;if(p>=25)return Caution;if(p>=10)return Warning;return Critical;}
Color StateColor(string state){string s=state.ToUpper();if(s.Contains("READY")||s.Contains("SAFE")||s.Contains("NO DAMAGE"))return Safe;if(s.Contains("CAUTION")||s.Contains("CHARGING")||s.Contains("HEAVY"))return Caution;if(s.Contains("DO NOT")||s.Contains("CRITICAL")||s.Contains("DAMAGED")||s.Contains("REPAIR"))return Critical;return Warning;}
string CargoState(){if(_m.CargoPercent>95)return"FULL";if(_m.CargoPercent>85)return"HEAVY";return"OK";}
string PlanetEntryState(){if(_m.NaturalGravity<=0.01f)return"SPACE";if(_m.DescentState==null||_m.DescentState=="")return"SCANNING";return _m.DescentState;}
Color LiftStatusColor(){if(_m.NaturalGravity<=0.01f)return Muted;if(_m.LiftCount==0||_m.LiftOnline==0)return Critical;if(_m.LiftWithAtmoPct<100f)return Critical;if(_m.LiftReliablePct<100f)return Warning;if(_m.LiftReliablePct<150f||_m.LiftOnline<_m.LiftCount)return Caution;return Safe;}
string TurretState(){if(_m.TurretCount==0)return"NO TURRETS";if(_m.TurretDamaged>0)return"DAMAGED";if(_m.TurretOnline<_m.TurretCount)return"PARTIAL";return"READY";}
string PressureState(){if(_m.VentCount==0)return"NO VENTS";if(_m.PressurePercent>=95)return"PRESSURIZED";if(_m.PressurePercent>=50)return"PARTIAL";return"LEAK / NO AIR";}
string LifeSupportReason(){if(_m.VentCount==0)return"No monitored vents";if(_m.DepressurizeVents>0)return _m.DepressurizeVents+" vent(s) depressurizing";if(_m.VentOnline<_m.VentCount)return(_m.VentCount-_m.VentOnline)+" vent(s) offline";int leakCount=0;if(_m.LeakVent1!="-")leakCount++;if(_m.LeakVent2!="-")leakCount++;if(_m.LeakVent3!="-")leakCount++;if(leakCount>0)return leakCount+" vent(s) not sealed - see below";if(_m.PressurePercent<95f&&_m.PressurizedVents<_m.VentCount)return _m.PressurizedVents+"/"+_m.VentCount+" vents pressurizing";return"All monitored vents sealed";}
string ReactorUraniumSummary(){MyItemType uranium=MyItemType.MakeIngot("Uranium");double total=0;int withFuel=0;int depleted=0;for(int i=0;i<_reactors.Count;i++){IMyPowerProducer p=_reactors[i];IMyTerminalBlock b=p as IMyTerminalBlock;if(b==null||b.InventoryCount==0)continue;double amount=(double)b.GetInventory(0).GetItemAmount(uranium);total+=amount;if(amount>0)withFuel++;else if(p.IsWorking)depleted++;}_m.ReactorDepleted=depleted;return FormatKg(total)+"  fuelled "+withFuel+"/"+_reactors.Count;}
void SetReactorFuelLines(){_m.ReactorFuel1="-";_m.ReactorFuel2="-";MyItemType uranium=MyItemType.MakeIngot("Uranium");for(int i=0;i<_reactors.Count&&i<2;i++){IMyTerminalBlock b=_reactors[i]as IMyTerminalBlock;double amount=0;if(b!=null&&b.InventoryCount>0)amount=(double)b.GetInventory(0).GetItemAmount(uranium);string line=CleanBlockName(b==null?"Reactor":b.CustomName)+"  "+FormatKg(amount);if(i==0)_m.ReactorFuel1=line;else _m.ReactorFuel2=line;}}
float BlockIntegrity(IMyTerminalBlock block){IMySlimBlock slim=block.CubeGrid.GetCubeBlock(block.Position);if(slim==null||slim.MaxIntegrity<=0)return 100f;float current=slim.BuildIntegrity-slim.CurrentDamage;return Clamp(100f*current/slim.MaxIntegrity,0,100);}
string JumpEtaText(double remainingMWh,double rateMw){if(_m.JumpCount==0)return"-";if(_m.JumpPercent>=99.5f)return"READY";if(rateMw<=0.001){if(_m.JumpOnline>0&&_m.BatteryPercent>1f)return"measuring...";return"not charging";}double hours=remainingMWh/rateMw;double seconds=hours*3600.0;if(seconds<60)return seconds.ToString("0")+" sec";if(seconds<3600)return(seconds/60.0).ToString("0.0")+" min";return(seconds/3600.0).ToString("0.0")+" hr";}
string ShortItemName(MyItemType type){string s=type.SubtypeId;if(s=="")s=type.TypeId.ToString();int p=s.LastIndexOf('/');if(p>=0&&p+1<s.Length)s=s.Substring(p+1);return s.Replace("MyObjectBuilder_","");}
string CleanBlockName(string name){string n=name;n=n.Replace(LcdNameTag,"").Replace(CornerLcdNameTag,"");if(n.Length>26)n=n.Substring(0,26);return n.Trim();}
void SetTopCargoItems(Dictionary<string,double>items){_m.CargoItem1="none";_m.CargoItem2="-";_m.CargoItem3="-";for(int slot=0;slot<3;slot++){string bestKey="";double bestAmount=-1;foreach(KeyValuePair<string,double>kv in items){if(kv.Value>bestAmount){bestKey=kv.Key;bestAmount=kv.Value;}}if(bestKey=="")return;string line=bestKey+"  "+bestAmount.ToString("0.##");if(slot==0)_m.CargoItem1=line;else if(slot==1)_m.CargoItem2=line;else _m.CargoItem3=line;items.Remove(bestKey);}}
string ThrusterState(){if(_m.ThrusterCount==0)return"NO THRUSTERS";if(_m.ThrusterOnline<_m.ThrusterCount)return"PARTIAL";if(_m.GravityPercent>1&&(_m.LiftCount==0||_m.LiftOnline==0))return"NO LIFT";if(_m.GravityPercent>1&&_m.LiftCapacityPercent<100)return"LOW LIFT";return"READY";}
Color ThrusterStateColor(){string state=ThrusterState();if(state=="READY")return Safe;if(state=="PARTIAL")return Caution;return Critical;}
string ThrusterGroupState(int online,int count){if(count==0)return"not set";if(online==0)return"disabled 0/"+count;if(online<count)return"partial "+online+"/"+count;return"enabled "+online+"/"+count;}
Color TurretLineColor(string line){if(line=="-")return Muted;if(line.Contains("DAMAGED")||line.Contains("OFFLINE")||line.EndsWith("ammo 0"))return Critical;return Safe;}
string TurretStatusLine(IMyLargeTurretBase t){double ammo=0;for(int inv=0;inv<t.InventoryCount;inv++){_items.Clear();t.GetInventory(inv).GetItems(_items);for(int i=0;i<_items.Count;i++)ammo+=(double)_items[i].Amount;}string state=!t.IsFunctional?"DAMAGED":(t.IsWorking?"ONLINE":"OFFLINE");return CleanBlockName(t.CustomName)+"  "+state+"  ammo "+ammo.ToString("0");}
Color BatteryColor(float pct){if(pct>=60f)return Safe;if(pct>=30f)return Caution;if(pct>=15f)return Warning;return Critical;}
void RunAutoReactorCharging(){if(!AutoReactorCharging)return;if(_reactors.Count==0)return;if(_m.BatteryCount==0)return;float lowPct=25f;float fullPct=99.5f;if(_m.BatteryPercent<lowPct){for(int i=0;i<_reactors.Count;i++){IMyFunctionalBlock r=_reactors[i]as IMyFunctionalBlock;if(r!=null&&!r.Enabled)r.Enabled=true;}}else if(_m.BatteryPercent>=fullPct){for(int i=0;i<_reactors.Count;i++){IMyFunctionalBlock r=_reactors[i]as IMyFunctionalBlock;if(r!=null&&r.Enabled)r.Enabled=false;}}}
string PowerStateText(){if(_m.BatteryCount==0&&_m.ReactorCount==0&&_m.HydrogenEngineCount==0&&_m.SolarCount==0)return"NO POWER";if(_m.BatteryPercent<10)return"CRITICAL";if(_m.BatteryPercent<25)return"BATTERY LOW";if(_m.PowerInputMw>_m.PowerOutputMw&&_m.BatteryPercent<99)return"CHARGING";return"STABLE";}
Color PowerStateColor(){string state=PowerStateText();if(state=="STABLE")return Safe;if(state=="CHARGING")return Caution;return Critical;}
string FuelStateText(){if(_m.HydrogenCount==0)return"NO H2 TANKS";if(_m.FuelPercent<10)return"CRITICAL";if(_m.FuelPercent<25)return"LOW";if(_m.HydrogenImbalance>15)return"IMBALANCE";return"ONLINE";}
string FormatPct(float p){return p.ToString("0")+"%";}
string FormatKg(double kg){if(kg>=1000000)return(kg/1000000.0).ToString("0.00")+" Mkg";if(kg>=1000)return(kg/1000.0).ToString("0.0")+" t";return kg.ToString("0")+" kg";}
string FormatMW(double mw){if(mw>=1000)return(mw/1000.0).ToString("0.00")+" GW";if(mw>=1)return mw.ToString("0.00")+" MW";return(mw*1000.0).ToString("0")+" kW";}
string FormatMWh(double mwh){if(mwh>=1000)return(mwh/1000.0).ToString("0.00")+" GWh";return mwh.ToString("0.00")+" MWh";}
void DrawShield(MySpriteDrawFrame frame,Vector2 center,float size,float thickness,Color color){float w=size*0.58f;float h=size*0.70f;Vector2 top=center+new Vector2(0,-h*0.48f);Vector2 upperLeft=center+new Vector2(-w*0.42f,-h*0.31f);Vector2 leftMid=center+new Vector2(-w*0.42f,h*0.10f);Vector2 lowerLeft=center+new Vector2(-w*0.28f,h*0.34f);Vector2 bottom=center+new Vector2(0,h*0.50f);Vector2 lowerRight=center+new Vector2(w*0.28f,h*0.34f);Vector2 rightMid=center+new Vector2(w*0.42f,h*0.10f);Vector2 upperRight=center+new Vector2(w*0.42f,-h*0.31f);DrawLine(frame,top,upperLeft,thickness,color);DrawLine(frame,upperLeft,leftMid,thickness,color);DrawLine(frame,leftMid,lowerLeft,thickness,color);DrawLine(frame,lowerLeft,bottom,thickness,color);DrawLine(frame,bottom,lowerRight,thickness,color);DrawLine(frame,lowerRight,rightMid,thickness,color);DrawLine(frame,rightMid,upperRight,thickness,color);DrawLine(frame,upperRight,top,thickness,color);}
void DrawCrosshair(MySpriteDrawFrame frame,Vector2 center,float size,float thickness,Color white,Color red,float pulse){float half=size*0.50f;float gap=size*0.23f;float ring=size*0.58f;float spike=size*0.18f;DrawCircleOutline(frame,center,ring,thickness,white);DrawLine(frame,center+new Vector2(-half,0),center+new Vector2(-gap,0),thickness,white);DrawLine(frame,center+new Vector2(gap,0),center+new Vector2(half,0),thickness,white);DrawLine(frame,center+new Vector2(0,-half),center+new Vector2(0,-gap),thickness,white);DrawLine(frame,center+new Vector2(0,gap),center+new Vector2(0,half),thickness,white);DrawTriangle(frame,center+new Vector2(0,-ring*0.50f-spike*0.35f),new Vector2(spike,spike*1.8f),0f,white);DrawTriangle(frame,center+new Vector2(0,ring*0.50f+spike*0.35f),new Vector2(spike,spike*1.8f),(float)Math.PI,white);DrawCircle(frame,center,size*(0.16f+0.08f*pulse),red);}
void DrawBox(MySpriteDrawFrame frame,Vector2 center,Vector2 size,Color color){MySprite sprite=MySprite.CreateSprite("SquareSimple",center,size);sprite.Color=color;frame.Add(sprite);}
void DrawRectOutline(MySpriteDrawFrame frame,Vector2 center,Vector2 size,float thickness,Color color){float left=center.X-size.X*0.5f;float right=center.X+size.X*0.5f;float top=center.Y-size.Y*0.5f;float bottom=center.Y+size.Y*0.5f;DrawLine(frame,new Vector2(left,top),new Vector2(right,top),thickness,color);DrawLine(frame,new Vector2(right,top),new Vector2(right,bottom),thickness,color);DrawLine(frame,new Vector2(right,bottom),new Vector2(left,bottom),thickness,color);DrawLine(frame,new Vector2(left,bottom),new Vector2(left,top),thickness,color);}
void DrawCornerTicks(MySpriteDrawFrame frame,Vector2 center,Vector2 size,float length,float thickness,Color color){float left=center.X-size.X*0.5f;float right=center.X+size.X*0.5f;float top=center.Y-size.Y*0.5f;float bottom=center.Y+size.Y*0.5f;DrawLine(frame,new Vector2(left,top),new Vector2(left+length,top),thickness,color);DrawLine(frame,new Vector2(left,top),new Vector2(left,top+length),thickness,color);DrawLine(frame,new Vector2(right,top),new Vector2(right-length,top),thickness,color);DrawLine(frame,new Vector2(right,top),new Vector2(right,top+length),thickness,color);DrawLine(frame,new Vector2(left,bottom),new Vector2(left+length,bottom),thickness,color);DrawLine(frame,new Vector2(left,bottom),new Vector2(left,bottom-length),thickness,color);DrawLine(frame,new Vector2(right,bottom),new Vector2(right-length,bottom),thickness,color);DrawLine(frame,new Vector2(right,bottom),new Vector2(right,bottom-length),thickness,color);}
void DrawCircle(MySpriteDrawFrame frame,Vector2 center,float diameter,Color color){MySprite sprite=MySprite.CreateSprite("Circle",center,new Vector2(diameter,diameter));sprite.Color=color;frame.Add(sprite);}
void DrawCircleOutline(MySpriteDrawFrame frame,Vector2 center,float diameter,float thickness,Color color){MySprite outer=MySprite.CreateSprite("Circle",center,new Vector2(diameter,diameter));outer.Color=color;frame.Add(outer);MySprite inner=MySprite.CreateSprite("Circle",center,new Vector2(diameter-thickness*2.2f,diameter-thickness*2.2f));inner.Color=Bg;frame.Add(inner);}
void DrawLine(MySpriteDrawFrame frame,Vector2 a,Vector2 b,float thickness,Color color){Vector2 delta=b-a;float length=delta.Length();Vector2 center=(a+b)*0.5f;float angle=(float)Math.Atan2(delta.Y,delta.X);MySprite sprite=MySprite.CreateSprite("SquareSimple",center,new Vector2(length,thickness));sprite.Color=color;sprite.RotationOrScale=angle;frame.Add(sprite);}
void DrawTriangle(MySpriteDrawFrame frame,Vector2 center,Vector2 size,float rotation,Color color){MySprite sprite=MySprite.CreateSprite("Triangle",center,size);sprite.Color=color;sprite.RotationOrScale=rotation;frame.Add(sprite);}
void DrawTitleOrnament(MySpriteDrawFrame frame,float x,float y,float width,float thickness,Color color){float gap=width*0.055f;float notch=width*0.055f;DrawLine(frame,new Vector2(x-width*0.50f,y),new Vector2(x-gap,y),thickness,color);DrawLine(frame,new Vector2(x+gap,y),new Vector2(x+width*0.50f,y),thickness,color);DrawLine(frame,new Vector2(x-gap,y),new Vector2(x,y+notch),thickness,color);DrawLine(frame,new Vector2(x,y+notch),new Vector2(x+gap,y),thickness,color);}
void DrawText(MySpriteDrawFrame frame,string value,Vector2 position,float scale,Color color,TextAlignment align){MySprite sprite=MySprite.CreateText(value,"White",color,scale,align);sprite.Position=position;frame.Add(sprite);}
class ScreenTarget{public string Name;public string Page;public IMyTextSurface Surface;public bool Compact;public string Layout;public ScreenTarget(string name,string page,IMyTextSurface surface,bool compact,string layout){Name=name;Page=page;Surface=surface;Compact=compact;Layout=layout;}}
class View{public Vector2 Offset;public Vector2 Size;public Vector2 Center;public float Left;public float Right;public float Top;public float Bottom;public float W;public float H;public float Unit;public View(Vector2 offset,Vector2 size){Offset=offset;Size=size;Center=offset+size*0.5f;Left=offset.X;Top=offset.Y;W=size.X;H=size.Y;Right=Left+W;Bottom=Top+H;Unit=Math.Min(W,H);}}
class Metrics{public string MasterState="READY";public Color MasterColor;public string FlightMode="MANUAL";public double BaseMassKg;public double TotalMassKg;public double CargoMassKg;public float CargoPercent;public float CargoDensityKgPerL;public int CargoBlocks;public float BatteryPercent;public int BatteryCount;public int BatteryOnline;public double BatteryStoredMWh;public double BatteryCapacityMWh;public double PowerInputMw;public double PowerOutputMw;public int ReactorCount;public int ReactorOnline;public string ReactorUranium="0 kg";public string ReactorFuel1="-";public string ReactorFuel2="-";public int ReactorDepleted;public int SolarCount;public int HydrogenEngineCount;public int HydrogenEngineOnline;public float FuelPercent;public int HydrogenCount;public int HydrogenOnline;public float HydrogenImbalance;public float OxygenPercent;public int OxygenCount;public int OxygenOnline;public int GasGeneratorCount;public int GasGeneratorOnline;public int GasGeneratorWorking;public double GeneratorIceKg;public float JumpPercent;public int JumpCount;public int JumpOnline;public int JumpDamaged;public string JumpState="NO DRIVES";public double JumpStoredMWh;public double JumpCapacityMWh;public double JumpChargeRateMw;public string JumpEta="-";public double JumpRangeKm;public int TurretCount;public int TurretOnline;public int TurretDamaged;public double AmmoMassKg;public int TurretDepleted;public int AmmoItemStacks;public string AmmoSample="none";public string TurretLine1="-";public string TurretLine2="-";public string TurretLine3="-";public string TurretLine4="-";public int VentCount;public int VentOnline;public int PressurizedVents;public int DepressurizeVents;public float PressurePercent;public string LifeSupportReason="";public string LeakVent1="-";public string LeakVent2="-";public string LeakVent3="-";public int ThrusterCount;public int ThrusterOnline;public int LiftCount;public int LiftOnline;public float LiftLoadPercent;public float LiftCapacityPercent;public 